const DEFAULT_API='https://cove-api.jeff-r-winters.workers.dev';
    const state={boats:[],captains:[],owners:[],bookings:[],availability:[],customers:[],customerRecords:[],settings:{},selectedBoatId:null,selectedCaptainId:null,selectedOwnerId:null,selectedCustomerId:null,selectedBookingId:null,settlementDrafts:{},lastSettlementEditAt:0,media:[],bookingView:'list',calendarMonth:new Date(new Date().getFullYear(),new Date().getMonth(),1),bookingFilters:{status:'',boatId:'',captainId:'',from:'',to:'',search:''}};
    const fields=['name','slug','status','lengthFt','capacity','bedrooms','bathrooms','make','model','type','homePort','shortDescription','startingPrice','priceUnit'];
    const captainFields=['captainName','captainStatus','captainCredential','captainEmail','captainPhone','captainHomePort','captainBio','captainPhotoUrl'];
    const sidePanel=window.AdminSidePanel?new AdminSidePanel():null;
    let captainCropper=null,coverCropper=null,coverCropDraft=null;
    const money=v=>new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0}).format(Number(v||0));
    const api=()=>localStorage.getItem('cove_api_base')||DEFAULT_API;
    const token=()=>localStorage.getItem('cove_admin_token')||'';
    const esc=value=>String(value??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
    const timeText=()=>new Date().toLocaleTimeString([], {hour:'numeric', minute:'2-digit'});
    apiBase.value=api();
    adminToken.value=token();
    function adminHeaders(extra={}){const headers={...extra};if(token())headers.Authorization=`Bearer ${token()}`;return headers;}
    function setButtonsBusy(ids,busy){ids.map(id=>document.getElementById(id)).filter(Boolean).forEach(btn=>{btn.disabled=busy;btn.dataset.defaultText ||= btn.textContent;btn.textContent=busy?'Saving...':btn.dataset.defaultText;});}
    function showAdminSaveStatus(anchorId,statusId,message,tone='good'){const anchor=document.getElementById(anchorId);if(!anchor)return;let el=document.getElementById(statusId);if(!el){el=document.createElement('p');el.id=statusId;el.className='muted admin-save-status';(anchor.closest('.actions')||anchor).after(el);}el.textContent=message;el.className=`muted admin-save-status show ${tone}`;}
    function updateAuthStatus(health){authStatus.textContent=token()?`Admin token saved locally. API protected writes: ${health?.adminAuth?'enabled':'unknown'}.`:'No admin token saved.';}
    saveApiBase.onclick=async()=>{setButtonsBusy(['saveApiBase'],true);showAdminSaveStatus('saveApiBase','apiSaveStatus','Saving API settings...','info');try{localStorage.setItem('cove_api_base',apiBase.value.trim()||DEFAULT_API);localStorage.setItem('cove_admin_token',adminToken.value.trim());await Promise.all([loadHealth(),loadSettings(),loadBoats(),loadOwners(),loadCustomers()]);showAdminSaveStatus('saveApiBase','apiSaveStatus','API settings saved.');}catch(e){showAdminSaveStatus('saveApiBase','apiSaveStatus',e.message||'Could not save API settings','bad');}finally{setButtonsBusy(['saveApiBase'],false);}};
    clearAdminToken.onclick=()=>{localStorage.removeItem('cove_admin_token');adminToken.value='';updateAuthStatus();};
    function go(tab){document.querySelectorAll('.tab').forEach(t=>t.classList.toggle('active',t.id===tab));document.querySelectorAll('[data-tab]').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));if(tab==='dashboard')renderBookingKanban();if(tab==='boats')showBoatList();if(tab==='captains')renderCaptains();if(tab==='owners')renderOwners();if(tab==='customers')renderCustomers();if(tab==='bookings')renderBookings();if(tab==='reporting')renderReporting();if(tab==='json')renderJson();}
    document.querySelectorAll('[data-tab]').forEach(b=>b.addEventListener('click',()=>go(b.dataset.tab)));
    function showBoatList(){state.selectedBoatId=null;state.media=[];boatListScreen.classList.remove('hidden');boatDetailScreen.classList.add('hidden');}
    function showBoatDetail(){boatListScreen.classList.add('hidden');boatDetailScreen.classList.remove('hidden');scrollTo({top:0,behavior:'smooth'});}
    function updateStats(){statBoats.textContent=state.boats.length;bindHalfHourTimes(bookingList);bindSettlementInputs();updateBookingBadges();}
    function updateBookingBadges(){const newCount=state.bookings.filter(b=>b.status==='requested').length;statNewBookings.textContent=newCount;statBookings.textContent=state.bookings.length;statReviewingBookings.textContent=state.bookings.filter(b=>b.status==='reviewing').length;statConfirmedBookings.textContent=state.bookings.filter(b=>b.status==='confirmed').length;bookingNavCount.textContent=newCount;bookingNavCount.classList.toggle('hidden',newCount===0);mobileBookingCount.textContent=newCount?`(${newCount})`:'';renderBookingKanban();}
    async function loadHealth(){try{const r=await fetch(`${api()}/api/v1/health`);const d=await r.json();updateAuthStatus(d);}catch{updateAuthStatus();}}
    async function loadSettings(){try{const r=await fetch(`${api()}/api/v1/settings`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Settings unavailable');state.settings=Object.fromEntries(d.map(row=>[row.key,row.value_type==='number'?Number(row.value):row.value]));if(document.getElementById('bookings')?.classList.contains('active'))renderBookings();}catch(e){console.warn('Cove settings unavailable',e);}}
    async function loadBoats(){boatLoadStatus.textContent='Loading boats from Cove API...';try{const r=await fetch(`${api()}/api/v1/boats`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load boats');state.boats=d;renderBoats();if(state.selectedOwnerId)renderOwnerBoatAssignments();}catch(e){boatLoadStatus.textContent=e.message;boatList.innerHTML='<div class="item">Could not load boats from API.</div>';}}
    function orderedBoats(){return [...state.boats].sort((a,b)=>Number(a.sortOrder||0)-Number(b.sortOrder||0)||String(a.name||'').localeCompare(String(b.name||'')));}
    function renderBoats(){const boats=orderedBoats();boatList.innerHTML=boats.map((b,i)=>`<article class="item click" draggable="true" data-id="${esc(b.id)}"><div class="item-top"><div><h3>${esc(b.name)}</h3><p>${b.lengthFt||'--'} ft | ${b.capacity||'--'} guests | ${b.startingPrice?money(b.startingPrice):'Contact for pricing'}</p></div><span class="badge ${b.status==='active'?'good':'bad'}">Open</span></div><div class="pill-row"><span class="pill">Display ${i+1}</span><span class="pill">${esc(b.status)}</span><span class="pill">${b.featured?'Featured':'Standard'}</span><span class="pill">${b.bookingEnabled?'Booking enabled':'Booking disabled'}</span><span class="pill">${esc(b.ownerName||'No owner')}</span><span class="pill">${(b.approvedCaptainIds||[]).length} approved captains</span></div></article>`).join('')||'<div class="item">No boats found.</div>';boatList.querySelectorAll('.item.click').forEach(i=>i.onclick=()=>selectBoat(i.dataset.id));bindBoatDrag();boatLoadStatus.textContent=`${state.boats.length} boat records loaded from D1. Drag boat cards to change public display order.`;renderBookingFilters();renderOwnerOptions();if(state.selectedCaptainId)renderCaptainBoatApprovals();if(state.selectedOwnerId)renderOwnerBoatAssignments();updateStats();renderJson();}
    function bindBoatDrag(){boatList.querySelectorAll('[draggable="true"]').forEach(card=>{card.ondragstart=e=>{card.classList.add('dragging');e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain',card.dataset.id);};card.ondragend=()=>card.classList.remove('dragging');card.ondragover=e=>{e.preventDefault();e.dataTransfer.dropEffect='move';};card.ondrop=e=>{e.preventDefault();reorderBoats(e.dataTransfer.getData('text/plain'),card.dataset.id).catch(err=>alert(err.message));};});}
    async function reorderBoats(sourceId,targetId){if(!sourceId||!targetId||sourceId===targetId)return;const boats=orderedBoats();const from=boats.findIndex(b=>b.id===sourceId);const to=boats.findIndex(b=>b.id===targetId);if(from<0||to<0)return;const [moved]=boats.splice(from,1);boats.splice(to,0,moved);const boatIds=boats.map(b=>b.id);state.boats=state.boats.map(b=>({...b,sortOrder:boatIds.indexOf(b.id)}));renderBoats();boatLoadStatus.textContent='Saving public boat order...';const r=await fetch(`${api()}/api/v1/boats/order`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({boatIds})});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not save boat order');boatLoadStatus.textContent='Public boat order saved.';await loadBoats();}
    function selectBoat(id){state.selectedBoatId=id;const b=state.boats.find(x=>x.id===id);if(!b)return;showBoatDetail();boatBreadcrumbName.textContent=b.name||'Boat Details';detailTitle.textContent=b.name;detailSummary.textContent=b.shortDescription||'';detailStatus.textContent=b.status||'boat';detailPills.innerHTML=[`${b.lengthFt||'--'} ft`,`${b.capacity||'--'} guests`,b.startingPrice?money(b.startingPrice):'No price',b.featured?'Featured':'Standard',b.ownerName?`Owner: ${b.ownerName}`:'No owner'].map(x=>`<span class="pill">${x}</span>`).join('');fields.forEach(f=>document.getElementById(f).value=b[f]??'');featured.value=String(Boolean(b.featured));bookingEnabled.value=String(Boolean(b.bookingEnabled));renderOwnerOptions();if(window.ownerId)ownerId.value=b.ownerId||'';renderBoatCaptainApprovals();loadMedia().catch(e=>renderMediaError(e.message));}
    function formBoat(){const cur=state.boats.find(x=>x.id===state.selectedBoatId)||{};const next={...cur};fields.forEach(f=>next[f]=['lengthFt','capacity','bedrooms','bathrooms','startingPrice'].includes(f)?Number(document.getElementById(f).value||0):document.getElementById(f).value);next.ownerId=window.ownerId?ownerId.value||null:null;next.featured=featured.value==='true';next.bookingEnabled=bookingEnabled.value==='true';next.lifecycleStatus=next.status==='active'?'marketable':'draft';return next;}
    async function saveCurrentBoat(){setButtonsBusy(['saveBoat','saveBoatCompact'],true);showAdminSaveStatus('saveBoat','boatSaveStatus','Saving boat...','info');try{const next=formBoat();const isNew=!state.boats.find(b=>b.id===next.id);const url=isNew?`${api()}/api/v1/boats`:`${api()}/api/v1/boats/${encodeURIComponent(next.id)}`;const r=await fetch(url,{method:isNew?'POST':'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(next)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Save failed');await loadBoats();selectBoat(next.id||d.id);showAdminSaveStatus('saveBoat','boatSaveStatus','Boat saved.');}catch(e){showAdminSaveStatus('saveBoat','boatSaveStatus',e.message||'Could not save boat','bad');throw e;}finally{setButtonsBusy(['saveBoat','saveBoatCompact'],false);}}
    saveBoat.onclick=()=>saveCurrentBoat().catch(()=>{});
    saveBoatCompact.onclick=()=>saveCurrentBoat().catch(()=>{});
    deleteBoat.onclick=async()=>{if(!state.selectedBoatId||!confirm('Delete this boat from D1?'))return;const r=await fetch(`${api()}/api/v1/boats/${encodeURIComponent(state.selectedBoatId)}`,{method:'DELETE',headers:adminHeaders()});const d=await r.json();if(!r.ok){alert(d.error||'Delete failed');return;}await loadBoats();showBoatList();};
    backToBoats.onclick=()=>{renderBoats();showBoatList();};
    boatBreadcrumb.onclick=()=>{renderBoats();showBoatList();};
    addBoat.onclick=()=>{const id=`boat_${Date.now()}`;state.boats.push({id,slug:`new-boat-${Date.now()}`,name:'New Cove Boat',status:'draft',lifecycleStatus:'draft',ownerId:null,bookingEnabled:false,featured:false,sortOrder:state.boats.length,homePort:'Lake of the Ozarks, MO',lengthFt:0,capacity:0,bedrooms:0,bathrooms:0,make:'',model:'',type:'Type TBD',shortDescription:'',startingPrice:0,priceUnit:'4 hour'});renderBoats();selectBoat(id);};
    function ensureBoatOwnerSelect(){if(document.getElementById('ownerId'))return;bookingEnabled.closest('label').insertAdjacentHTML('afterend','<label>Owner<select id="ownerId"><option value="">No owner assigned</option></select></label>');renderOwnerOptions();}
    function ensureOwnerUi(){if(document.getElementById('owners'))return;document.getElementById('customers').insertAdjacentHTML('beforebegin','<section class="tab" id="owners"><section class="page-head"><h1>Owners</h1><p>Manage boat owners and assign boats from either side of the operation.</p></section><section class="admin-sticky-detail-bar"><nav class="admin-breadcrumb"><button id="ownerBreadcrumb" type="button">Owners</button><span class="sep">›</span><strong id="ownerBreadcrumbName">New Owner</strong></nav><div class="admin-sticky-actions"><button class="btn sand admin-save-compact" type="button" id="saveOwnerCompact">Save Owner</button></div></section><div class="panel"><div class="panel-head"><h2>Owner profile</h2></div><div class="panel-body"><form class="form"><label>Name<input id="ownerName"></label><label>Status<select id="ownerStatus"><option value="active">active</option><option value="draft">draft</option><option value="inactive">inactive</option></select></label><label>Email<input id="ownerEmail" type="email"></label><label>Phone<input id="ownerPhone"></label><label class="full">Payout notes<textarea id="ownerPayoutNotes"></textarea></label><div class="actions full"><button class="btn sand" type="button" id="saveOwner">Save Owner</button><button class="btn light" type="button" id="newOwner">New Owner</button><button class="btn danger" type="button" id="deleteOwner">Delete Owner</button></div></form></div></div><div class="panel"><div class="panel-head"><h2>Owned boats</h2></div><div class="panel-body"><div id="ownerBoatAssignments" class="list"></div><p class="muted" id="ownerBoatStatus">Choose which boats belong to this owner.</p></div></div><div class="toolbar"><p class="muted" id="ownerLoadStatus">Loading owners...</p><button class="btn light" id="reloadOwners" type="button">Reload</button></div><div class="list" id="ownerList"></div></section>');saveOwner.onclick=()=>saveCurrentOwner().catch(()=>{});saveOwnerCompact.onclick=()=>saveCurrentOwner().catch(()=>{});newOwner.onclick=blankOwner;ownerBreadcrumb.onclick=blankOwner;deleteOwner.onclick=deleteCurrentOwner;reloadOwners.onclick=loadOwners;}
    function renderOwnerOptions(){ensureBoatOwnerSelect();const select=document.getElementById('ownerId');if(!select)return;const current=state.selectedBoatId?state.boats.find(b=>b.id===state.selectedBoatId)?.ownerId:select.value;const missing=current&&!state.owners.some(o=>o.id===current)?`<option value="${esc(current)}">Unmatched owner (${esc(current)})</option>`:'';select.innerHTML='<option value="">No owner assigned</option>'+missing+state.owners.map(o=>`<option value="${esc(o.id)}">${esc(o.name)}</option>`).join('');select.value=current||'';}
    async function loadOwners(){ensureOwnerUi();ownerLoadStatus.textContent='Loading owners from Cove API...';try{const r=await fetch(`${api()}/api/v1/owners`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load owners');state.owners=d;renderOwners();renderOwnerOptions();if(state.selectedOwnerId)renderOwnerBoatAssignments();}catch(e){ownerLoadStatus.textContent=e.message;ownerList.innerHTML='<div class="item">Could not load owners from API.</div>';}}
    function renderOwners(){ensureOwnerUi();ownerList.innerHTML=state.owners.map(o=>`<article class="item click" data-id="${esc(o.id)}"><div class="item-top"><div><h3>${esc(o.name)}</h3><p>${esc(o.email||'No email')} | ${esc(o.phone||'No phone')}</p></div><span class="badge ${o.status==='active'?'good':'bad'}">${esc(o.status)}</span></div><div class="pill-row"><span class="pill">${Number(o.boatCount||0)} boat${Number(o.boatCount||0)===1?'':'s'}</span><span class="pill">${esc(o.payoutNotes?'Payout notes':'No payout notes')}</span></div></article>`).join('')||'<div class="item">No owners yet.</div>';ownerList.querySelectorAll('.item.click').forEach(i=>i.onclick=()=>selectOwner(i.dataset.id));ownerLoadStatus.textContent=`${state.owners.length} owner records loaded from D1`;}
    function selectOwner(id){ensureOwnerUi();state.selectedOwnerId=id;const o=state.owners.find(x=>x.id===id);if(!o)return;ownerBreadcrumbName.textContent=o.name||'Owner';ownerName.value=o.name||'';ownerStatus.value=o.status||'active';ownerEmail.value=o.email||'';ownerPhone.value=o.phone||'';ownerPayoutNotes.value=o.payoutNotes||'';renderOwnerBoatAssignments();}
    function blankOwner(){ensureOwnerUi();state.selectedOwnerId=null;ownerBreadcrumbName.textContent='New Owner';ownerName.value='';ownerStatus.value='active';ownerEmail.value='';ownerPhone.value='';ownerPayoutNotes.value='';renderOwnerBoatAssignments();}
    function formOwner(){return {id:state.selectedOwnerId,name:ownerName.value,status:ownerStatus.value,email:ownerEmail.value,phone:ownerPhone.value,payoutNotes:ownerPayoutNotes.value};}
    async function saveCurrentOwner(){ensureOwnerUi();setButtonsBusy(['saveOwner','saveOwnerCompact'],true);showAdminSaveStatus('saveOwner','ownerSaveStatus','Saving owner...','info');try{const next=formOwner();const isNew=!next.id;const url=isNew?`${api()}/api/v1/owners`:`${api()}/api/v1/owners/${encodeURIComponent(next.id)}`;const r=await fetch(url,{method:isNew?'POST':'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(next)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Save owner failed');await loadOwners();selectOwner(next.id||d.id);showAdminSaveStatus('saveOwner','ownerSaveStatus','Owner saved.');}catch(e){showAdminSaveStatus('saveOwner','ownerSaveStatus',e.message||'Could not save owner','bad');throw e;}finally{setButtonsBusy(['saveOwner','saveOwnerCompact'],false);}}
    async function deleteCurrentOwner(){if(!state.selectedOwnerId||!confirm('Delete this owner from D1? Boats assigned to this owner will be unassigned.'))return;const r=await fetch(`${api()}/api/v1/owners/${encodeURIComponent(state.selectedOwnerId)}`,{method:'DELETE',headers:adminHeaders()});const d=await r.json();if(!r.ok){alert(d.error||'Delete owner failed');return;}blankOwner();await loadOwners();await loadBoats();}
    function renderOwnerBoatAssignments(){ensureOwnerUi();const owner=state.owners.find(o=>o.id===state.selectedOwnerId);if(!owner){ownerBoatAssignments.innerHTML='<div class="empty-media">Select or save an owner before assigning boats.</div>';ownerBoatStatus.textContent='Choose which boats belong to this owner.';return;}ownerBoatAssignments.innerHTML=state.boats.length?orderedBoats().map(b=>`<label class="item"><span><input type="checkbox" data-owner-boat-id="${esc(b.id)}" ${b.ownerId===owner.id?'checked':''}> ${esc(b.name)}</span><span class="muted">${b.ownerId&&b.ownerId!==owner.id?`Currently owned by ${esc(b.ownerName||'another owner')}`:esc(b.status||'draft')}</span></label>`).join(''):'<div class="empty-media">Add boats before assigning them to an owner.</div>';ownerBoatAssignments.querySelectorAll('[data-owner-boat-id]').forEach(input=>input.onchange=saveOwnerBoatAssignments);ownerBoatStatus.textContent=`${Number(owner.boatCount||0)} owned boat(s).`;}
    async function saveOwnerBoatAssignments(){const owner=state.owners.find(o=>o.id===state.selectedOwnerId);if(!owner)return;const boatIds=[...ownerBoatAssignments.querySelectorAll('[data-owner-boat-id]:checked')].map(input=>input.dataset.ownerBoatId);ownerBoatStatus.textContent='Saving boat owner assignments...';const r=await fetch(`${api()}/api/v1/owners/${encodeURIComponent(owner.id)}/boats`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({boatIds})});const d=await r.json();if(!r.ok){ownerBoatStatus.textContent=d.error||'Could not save owner assignments';return;}ownerBoatStatus.textContent=`${boatIds.length} owned boat(s) saved.`;await loadBoats();await loadOwners();selectOwner(owner.id);}
    async function loadCaptains(){captainLoadStatus.textContent='Loading captains from Cove API...';try{const r=await fetch(`${api()}/api/v1/captains`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load captains');state.captains=d;renderCaptains();if(state.selectedBoatId)renderBoatCaptainApprovals();if(state.selectedCaptainId)renderCaptainBoatApprovals();}catch(e){captainLoadStatus.textContent=e.message;captainList.innerHTML='<div class="item">Could not load captains from API.</div>';}}
    function renderCaptains(){captainList.innerHTML=state.captains.map(c=>`<article class="item click" data-id="${esc(c.id)}"><div class="item-top"><div><h3>${esc(c.name)}</h3><p>${esc(c.credential||'Credential TBD')} | ${esc(c.homePort||'Home port TBD')}</p></div><span class="badge ${c.status==='active'?'good':'bad'}">${esc(c.status)}</span></div><div class="pill-row"><span class="pill">${Number(c.approvedBoatCount||0)} approved boats</span><span class="pill">${esc(c.email||'No email')}</span><span class="pill">${esc(c.phone||'No phone')}</span>${c.photoUrl?'<span class="pill">Photo ready</span>':'<span class="pill">No photo</span>'}</div></article>`).join('')||'<div class="item">No captains yet.</div>';captainList.querySelectorAll('.item.click').forEach(i=>i.onclick=()=>selectCaptain(i.dataset.id));captainLoadStatus.textContent=`${state.captains.length} captain records loaded from D1`;renderBookingFilters();}
    function initials(name){return String(name||'CC').split(/\s+/).filter(Boolean).slice(0,2).map(x=>x[0]).join('').toUpperCase()||'CC';}
    function cropNumber(value,fallback){const n=Number(value);return Number.isFinite(n)?n:fallback;}
    function setCaptainCropInputs(c={}){captainPhotoFocalX.value=cropNumber(c.photoFocalX??c.photo_focal_x,50);captainPhotoFocalY.value=cropNumber(c.photoFocalY??c.photo_focal_y,30);captainPhotoZoom.value=cropNumber(c.photoZoom??c.photo_zoom,1);}
    function updateCaptainPhotoPreview(){const url=captainPhotoUrl.value.trim();const root=document.getElementById('captainPhotoCropper');if(!root||!window.AdminImageCropper)return;const value={focalX:cropNumber(captainPhotoFocalX.value,50),focalY:cropNumber(captainPhotoFocalY.value,30),zoom:cropNumber(captainPhotoZoom.value,1)};if(!captainCropper){captainCropper=new AdminImageCropper(root,{imageUrl:url,...value,frame:'rounded-square',hint:'Adjust the public captain card framing. Save Captain to persist crop settings.',onChange:v=>{captainPhotoFocalX.value=v.focalX;captainPhotoFocalY.value=v.focalY;captainPhotoZoom.value=v.zoom;}});}else{captainCropper.setImage(url);captainCropper.setValue(value);}root.classList.toggle('hidden',!url);}
    function selectCaptain(id){state.selectedCaptainId=id;const c=state.captains.find(x=>x.id===id);if(!c)return;captainBreadcrumbName.textContent=c.name||'Captain';captainName.value=c.name||'';captainStatus.value=c.status||'draft';captainCredential.value=c.credential||'';captainEmail.value=c.email||'';captainPhone.value=c.phone||'';captainHomePort.value=c.homePort||'';captainBio.value=c.bio||'';captainPhotoUrl.value=c.photoUrl||'';setCaptainCropInputs(c);captainPhotoStatus.textContent=c.photoUrl?'Captain photo is set. Adjust crop and save as needed.':'Upload or paste a profile image URL.';updateCaptainPhotoPreview();renderCaptainBoatApprovals();}
    function blankCaptain(){state.selectedCaptainId=null;captainBreadcrumbName.textContent='New Captain';captainName.value='';captainStatus.value='draft';captainCredential.value='';captainEmail.value='';captainPhone.value='';captainHomePort.value='Lake of the Ozarks, MO';captainBio.value='';captainPhotoUrl.value='';captainPhotoFile.value='';setCaptainCropInputs();captainPhotoStatus.textContent='Upload, replace, paste, or crop a profile image.';updateCaptainPhotoPreview();renderCaptainBoatApprovals();}
    function formCaptain(){return {id:state.selectedCaptainId,name:captainName.value,status:captainStatus.value,credential:captainCredential.value,email:captainEmail.value,phone:captainPhone.value,homePort:captainHomePort.value,bio:captainBio.value,photoUrl:captainPhotoUrl.value.trim(),photoFocalX:cropNumber(captainPhotoFocalX.value,50),photoFocalY:cropNumber(captainPhotoFocalY.value,30),photoZoom:cropNumber(captainPhotoZoom.value,1)};}
    async function saveCurrentCaptain(){setButtonsBusy(['saveCaptain','saveCaptainCompact'],true);showAdminSaveStatus('saveCaptain','captainSaveStatus','Saving captain...','info');try{const next=formCaptain();const isNew=!next.id;const url=isNew?`${api()}/api/v1/captains`:`${api()}/api/v1/captains/${encodeURIComponent(next.id)}`;const r=await fetch(url,{method:isNew?'POST':'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(next)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Save captain failed');await loadCaptains();selectCaptain(next.id||d.id);showAdminSaveStatus('saveCaptain','captainSaveStatus','Captain saved.');}catch(e){showAdminSaveStatus('saveCaptain','captainSaveStatus',e.message||'Could not save captain','bad');throw e;}finally{setButtonsBusy(['saveCaptain','saveCaptainCompact'],false);}}
    function orderedCaptainsForBoat(boat){const approvedOrder=new Map((boat?.approvedCaptainIds||[]).map((id,index)=>[id,index]));return [...state.captains].sort((a,b)=>{const ai=approvedOrder.has(a.id)?approvedOrder.get(a.id):9999;const bi=approvedOrder.has(b.id)?approvedOrder.get(b.id):9999;return ai-bi||String(a.name||'').localeCompare(String(b.name||''));});}
    function renderBoatCaptainApprovals(){const boat=state.boats.find(b=>b.id===state.selectedBoatId);if(!boat){boatCaptainApprovals.innerHTML='';return;}const approved=new Set(boat.approvedCaptainIds||[]);const order=new Map((boat.approvedCaptainIds||[]).map((id,index)=>[id,index]));boatCaptainApprovals.innerHTML=state.captains.length?orderedCaptainsForBoat(boat).map(c=>{const isApproved=approved.has(c.id);return `<article class="item boat-captain-row ${isApproved?'approved':''}" data-boat-captain-row="${esc(c.id)}" draggable="${isApproved?'true':'false'}"><label><span><input type="checkbox" data-boat-captain-id="${esc(c.id)}" ${isApproved?'checked':''}> ${esc(c.name)}</span><span class="muted">${esc(c.credential||'Credential TBD')} | ${esc(c.status)}</span></label><div class="pill-row"><span class="pill">${isApproved?`Choice ${Number(order.get(c.id))+1}`:'Not shown to customers'}</span>${isApproved?'<span class="pill">Drag to prioritize</span>':''}</div></article>`;}).join(''):'<div class="empty-media">Add captains before assigning them to this boat.</div>';boatCaptainApprovals.querySelectorAll('[data-boat-captain-id]').forEach(input=>input.onchange=()=>saveBoatCaptainApprovals());bindBoatCaptainDrag();boatCaptainStatus.textContent=approved.size?`${approved.size} approved captain(s). Drag approved captains to set customer dropdown order.`:'Choose which captains are approved for this boat.';}
    function bindBoatCaptainDrag(){boatCaptainApprovals.querySelectorAll('[data-boat-captain-row][draggable="true"]').forEach(row=>{row.ondragstart=e=>{row.classList.add('dragging');e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain',row.dataset.boatCaptainRow);};row.ondragend=()=>row.classList.remove('dragging');row.ondragover=e=>{e.preventDefault();e.dataTransfer.dropEffect='move';};row.ondrop=e=>{e.preventDefault();reorderBoatCaptains(e.dataTransfer.getData('text/plain'),row.dataset.boatCaptainRow).catch(err=>{boatCaptainStatus.textContent=err.message||'Could not save captain priority';});};});}
    async function reorderBoatCaptains(sourceId,targetId){const boat=state.boats.find(b=>b.id===state.selectedBoatId);if(!boat||!sourceId||!targetId||sourceId===targetId)return;const captainIds=[...(boat.approvedCaptainIds||[])];const from=captainIds.indexOf(sourceId);const to=captainIds.indexOf(targetId);if(from<0||to<0)return;const [moved]=captainIds.splice(from,1);captainIds.splice(to,0,moved);boat.approvedCaptainIds=captainIds;renderBoatCaptainApprovals();boatCaptainStatus.textContent='Saving captain priority...';await saveBoatCaptainApprovals(captainIds);}
    async function saveBoatCaptainApprovals(nextCaptainIds){const boat=state.boats.find(b=>b.id===state.selectedBoatId);if(!boat)return;const captainIds=[...new Set(nextCaptainIds||[...boatCaptainApprovals.querySelectorAll('[data-boat-captain-id]:checked')].map(input=>input.dataset.boatCaptainId))];boatCaptainStatus.textContent='Saving captain approvals...';const r=await fetch(`${api()}/api/v1/boats/${encodeURIComponent(boat.id)}/captains`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({captainIds})});const d=await r.json();if(!r.ok){boatCaptainStatus.textContent=d.error||'Could not save captain approvals';return;}boat.approvedCaptainIds=captainIds;renderBoatCaptainApprovals();boatCaptainStatus.textContent=`${captainIds.length} approved captain(s) saved in customer display order.`;}
    function renderCaptainBoatApprovals(){const captain=state.captains.find(c=>c.id===state.selectedCaptainId);if(!captain){captainBoatApprovals.innerHTML='<div class="empty-media">Select or save a captain before assigning boats.</div>';captainBoatStatus.textContent='Choose which boats this captain is approved for.';return;}captainBoatApprovals.innerHTML=state.boats.length?state.boats.map(b=>`<label class="item"><span><input type="checkbox" data-captain-boat-id="${esc(b.id)}" ${(b.approvedCaptainIds||[]).includes(captain.id)?'checked':''}> ${esc(b.name)}</span><span class="muted">${esc(b.status||'draft')} | ${esc(b.homePort||'Home port TBD')}</span></label>`).join(''):'<div class="empty-media">Add boats before assigning them to this captain.</div>';captainBoatApprovals.querySelectorAll('[data-captain-boat-id]').forEach(input=>input.onchange=()=>saveCaptainBoatApproval(input));captainBoatStatus.textContent=`${Number(captain.approvedBoatCount||0)} approved boat(s).`;}
    async function saveCaptainBoatApproval(input){const captain=state.captains.find(c=>c.id===state.selectedCaptainId);const boat=state.boats.find(b=>b.id===input.dataset.captainBoatId);if(!captain||!boat)return;const current=new Set(boat.approvedCaptainIds||[]);if(input.checked)current.add(captain.id);else current.delete(captain.id);captainBoatStatus.textContent='Saving boat approval...';const captainIds=[...current];const r=await fetch(`${api()}/api/v1/boats/${encodeURIComponent(boat.id)}/captains`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({captainIds})});const d=await r.json();if(!r.ok){captainBoatStatus.textContent=d.error||'Could not save boat approval';input.checked=!input.checked;return;}boat.approvedCaptainIds=captainIds;await loadBoats();await loadCaptains();selectCaptain(captain.id);}
    async function loadBookings({silent=false}={}){if(!silent)bookingLoadStatus.textContent='Loading bookings from Cove API...';try{const r=await fetch(`${api()}/api/v1/bookings?ts=${Date.now()}`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load bookings');state.bookings=d;renderBookings();if(document.getElementById('customers')?.classList.contains('active'))renderCustomers();if(document.getElementById('reporting')?.classList.contains('active'))renderReporting();updateBookingBadges();bookingRefreshStatus.textContent=`Auto-refreshing every 10 seconds. Last updated ${timeText()}.`;}catch(e){bookingRefreshStatus.textContent=`Auto-refresh paused by an error at ${timeText()}: ${e.message}`;if(!silent){bookingLoadStatus.textContent=e.message;bookingList.innerHTML='<div class="item">Could not load bookings from API.</div>';}}}
    async function loadAvailability(){try{const r=await fetch(`${api()}/api/v1/availability?ts=${Date.now()}`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load availability');state.availability=d;renderBookings();}catch(e){availabilityStatusText.textContent=e.message;}}
    function ensureBookingUi(){const tab=document.getElementById('bookings');if(!tab||document.getElementById('bookingListScreen'))return;const listScreen=document.createElement('div');listScreen.id='bookingListScreen';[...tab.children].forEach(child=>listScreen.appendChild(child));tab.appendChild(listScreen);const pageHead=listScreen.querySelector('.page-head');pageHead?.insertAdjacentHTML('afterend','<div class="booking-view-tabs" role="tablist" aria-label="Booking views"><button class="active" type="button" data-booking-view="list">List View</button><button type="button" data-booking-view="calendar">Calendar View</button></div>');const editor=document.getElementById('bookingList');const calendarPanel=document.getElementById('bookingCalendar')?.closest('.panel');const availabilityPanel=document.getElementById('saveAvailability')?.closest('.panel');const statusToolbar=document.getElementById('bookingLoadStatus')?.closest('.toolbar');const refreshStatus=document.getElementById('bookingRefreshStatus');const summaryPanel=document.createElement('div');summaryPanel.className='panel booking-list-panel';summaryPanel.innerHTML='<div class="panel-head"><div class="toolbar"><h2>Bookings Summary</h2><span class="muted">Click a booking to drill into details</span></div></div><div class="panel-body"><div class="list" id="bookingSummaryList"></div></div>';editor.parentNode.insertBefore(summaryPanel,editor);calendarPanel?.classList.add('booking-calendar-panel');availabilityPanel?.classList.add('booking-calendar-panel');statusToolbar?.classList.add('booking-list-panel');refreshStatus?.classList.add('booking-list-panel');document.querySelectorAll('[data-booking-view]').forEach(btn=>btn.onclick=()=>setBookingView(btn.dataset.bookingView));const detailScreen=document.createElement('div');detailScreen.id='bookingDetailScreen';detailScreen.className='hidden';detailScreen.innerHTML='<section class="admin-sticky-detail-bar"><nav class="admin-breadcrumb"><button id="backToBookingList" type="button">Bookings</button><span class="sep">&rsaquo;</span><strong id="bookingBreadcrumbName">Booking Details</strong></nav><div class="admin-sticky-actions"><button class="btn sand admin-save-compact" type="button" id="saveBookingCompact">Save Booking</button></div></section><section class="detail-hero hidden"><span class="badge" id="bookingDetailStatus">booking</span><h1 id="bookingDetailTitle">Booking Details</h1><p id="bookingDetailSummary">Edit the selected booking record.</p><div class="pill-row" id="bookingDetailPills"></div></section><div id="bookingDetailMount"></div>';tab.appendChild(detailScreen);document.getElementById('bookingDetailMount').appendChild(editor);document.getElementById('backToBookingList').onclick=showBookingList;document.getElementById('saveBookingCompact').onclick=()=>{if(state.selectedBookingId)saveBooking(state.selectedBookingId).catch(e=>alert(e.message));};}
    function setBookingView(view){state.bookingView=view==='calendar'?'calendar':'list';document.querySelectorAll('[data-booking-view]').forEach(btn=>btn.classList.toggle('active',btn.dataset.bookingView===state.bookingView));document.querySelectorAll('.booking-list-panel').forEach(el=>el.classList.toggle('hidden',state.bookingView!=='list'));document.querySelectorAll('.booking-calendar-panel').forEach(el=>el.classList.toggle('hidden',state.bookingView!=='calendar'));}
    function showBookingList(){state.selectedBookingId=null;document.getElementById('bookingListScreen')?.classList.remove('hidden');document.getElementById('bookingDetailScreen')?.classList.add('hidden');renderBookings();scrollTo({top:0,behavior:'smooth'});}
    function showBookingDetail(){document.getElementById('bookingListScreen')?.classList.add('hidden');document.getElementById('bookingDetailScreen')?.classList.remove('hidden');}
    function selectBooking(id){state.selectedBookingId=id;showBookingDetail();renderBookings();scrollTo({top:0,behavior:'smooth'});}
    function snapHalfHour(input){if(!input?.value)return;const [h,m]=input.value.split(':').map(Number);if(Number.isNaN(h)||Number.isNaN(m))return;let total=h*60+m;total=Math.round(total/30)*30;if(total>=1440)total=1410;input.value=`${String(Math.floor(total/60)).padStart(2,'0')}:${String(total%60).padStart(2,'0')}`;}
    function bindHalfHourTimes(root=document){root.querySelectorAll('input[type="time"]').forEach(input=>{input.step=1800;input.setAttribute('list','halfHourTimes');input.onblur=()=>snapHalfHour(input);input.onchange=()=>snapHalfHour(input);});}
    function populateHalfHourTimes(){const list=document.getElementById('halfHourTimes');if(list)list.innerHTML=Array.from({length:48},(_,i)=>{const total=i*30;return `<option value="${String(Math.floor(total/60)).padStart(2,'0')}:${String(total%60).padStart(2,'0')}"></option>`}).join('');}
    function dateTimeValue(date,time,end=false){if(!date)return '';return `${date}T${time || (end ? '23:30' : '00:00')}`;}
    async function saveAvailabilityBlock(){[availabilityStartTime,availabilityEndTime].forEach(snapHalfHour);const [entityType,entityId]=availabilityResource.value.split(':');const endDate=availabilityEndDate.value&&availabilityEndDate.value>=availabilityStartDate.value?availabilityEndDate.value:availabilityStartDate.value;const payload={entityType,entityId,status:availabilityStatus.value,startAt:dateTimeValue(availabilityStartDate.value,availabilityStartTime.value),endAt:dateTimeValue(endDate,availabilityEndTime.value,true),notes:availabilityNotes.value};if(!payload.entityId||!payload.startAt||!payload.endAt){availabilityStatusText.textContent='Choose a resource and date range.';return;}if(payload.endAt<=payload.startAt){availabilityStatusText.textContent='End must be after start.';return;}availabilityStatusText.textContent='Saving availability block...';const r=await fetch(`${api()}/api/v1/availability`,{method:'POST',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(payload)});const d=await r.json();if(!r.ok){availabilityStatusText.textContent=d.error||'Could not save availability';return;}availabilityEndDate.value=endDate;availabilityNotes.value='';availabilityStatusText.textContent='Availability block saved.';await loadAvailability();}
    async function deleteAvailabilityBlock(id){if(!confirm('Delete this availability block?'))return;const r=await fetch(`${api()}/api/v1/availability/${encodeURIComponent(id)}`,{method:'DELETE',headers:adminHeaders()});const d=await r.json();if(!r.ok){alert(d.error||'Could not delete availability');return;}await loadAvailability();}
    const bookingStatuses=['requested','reviewing','confirmed','completed','declined','cancelled'];
    function bookingStatusLabel(status){return status==='reviewing'?'Needs Follow-up':status==='booked'?'confirmed':status==='cancelled'?'canceled':status;}
    function renderBookingFilters(){if(!bookingFilterStatus)return;const current={...state.bookingFilters};bookingFilterStatus.innerHTML='<option value="">All statuses</option>'+bookingStatuses.map(s=>`<option value="${s}">${esc(bookingStatusLabel(s))}</option>`).join('');bookingFilterBoat.innerHTML='<option value="">All boats</option>'+state.boats.map(b=>`<option value="${esc(b.id)}">${esc(b.name)}</option>`).join('');bookingFilterCaptain.innerHTML='<option value="">All captains</option>'+state.captains.map(c=>`<option value="${esc(c.id)}">${esc(c.name)}</option>`).join('');availabilityResource.innerHTML=state.boats.map(b=>`<option value="boat:${esc(b.id)}">Boat: ${esc(b.name)}</option>`).join('')+state.captains.map(c=>`<option value="captain:${esc(c.id)}">Captain: ${esc(c.name)}</option>`).join('');bookingFilterStatus.value=current.status;bookingFilterBoat.value=current.boatId;bookingFilterCaptain.value=current.captainId;bookingFilterFrom.value=current.from;bookingFilterTo.value=current.to;bookingFilterSearch.value=current.search;}
    function readBookingFilters(){state.bookingFilters={status:bookingFilterStatus.value,boatId:bookingFilterBoat.value,captainId:bookingFilterCaptain.value,from:bookingFilterFrom.value,to:bookingFilterTo.value,search:bookingFilterSearch.value.trim().toLowerCase()};}
    function bookingMatchesFilters(b){const f=state.bookingFilters;if(f.status&&b.status!==f.status)return false;if(f.boatId&&b.boatId!==f.boatId)return false;if(f.captainId&&b.captainId!==f.captainId)return false;if(f.from&&(!b.charterDate||b.charterDate<f.from))return false;if(f.to&&(!b.charterDate||b.charterDate>f.to))return false;if(f.search){const text=[b.customerName,b.email,b.phone,b.boatName,b.captainName,b.customerNotes,b.officeNotes,b.status].join(' ').toLowerCase();if(!text.includes(f.search))return false;}return true;}
    function availabilityMatchesFilters(a){const f=state.bookingFilters;if(f.boatId&&!(a.entityType==='boat'&&a.entityId===f.boatId))return false;if(f.captainId&&!(a.entityType==='captain'&&a.entityId===f.captainId))return false;if(f.from&&a.endAt.slice(0,10)<f.from)return false;if(f.to&&a.startAt.slice(0,10)>f.to)return false;if(f.search){const text=[a.status,a.notes,availabilityLabel(a)].join(' ').toLowerCase();if(!text.includes(f.search))return false;}return true;}
    function availabilityLabel(a){return a.entityType==='boat'?(state.boats.find(b=>b.id===a.entityId)?.name||a.entityId):(state.captains.find(c=>c.id===a.entityId)?.name||a.entityId);}
    function filteredBookings(){return [...state.bookings].filter(bookingMatchesFilters);}
    function bookingStart(b){return b.charterDate?`${b.charterDate}T${b.startTime||'00:00'}`:'';}
    function bookingEnd(b){if(!b.charterDate)return '';const start=new Date(bookingStart(b));start.setMinutes(start.getMinutes()+Number(b.durationHours||4)*60);return dateKey(start)+'T'+String(start.getHours()).padStart(2,'0')+':'+String(start.getMinutes()).padStart(2,'0');}
    function conflictsForBooking(b){const start=bookingStart(b);const end=bookingEnd(b);if(!start||!end)return [];return state.availability.filter(a=>(a.entityType==='boat'&&a.entityId===b.boatId||a.entityType==='captain'&&a.entityId===b.captainId)&&a.startAt<end&&a.endAt>start);}
    function possibleConflictNotes(b){return [b.customerNotes,b.officeNotes].filter(Boolean).filter(text=>/availability warning|may not be available|conflict/i.test(text));}
    function dateKey(date){return [date.getFullYear(),String(date.getMonth()+1).padStart(2,'0'),String(date.getDate()).padStart(2,'0')].join('-');}
    function renderCalendar(bookings=filteredBookings()){const month=state.calendarMonth;calendarTitle.textContent=month.toLocaleDateString([], {month:'long',year:'numeric'});const dated=bookings.filter(b=>b.charterDate);const blocks=state.availability.filter(availabilityMatchesFilters);calendarSummary.textContent=`${dated.length} dated booking(s) and ${blocks.length} boat/captain availability block(s) match the current filters.`;const byDate=dated.reduce((map,b)=>{(map[b.charterDate] ||= []).push({kind:'booking',item:b});return map;},{});blocks.forEach(a=>{const first=a.startAt.slice(0,10);(byDate[first] ||= []).push({kind:'availability',item:a});});const start=new Date(month.getFullYear(),month.getMonth(),1);start.setDate(start.getDate()-start.getDay());const end=new Date(start);end.setDate(start.getDate()+41);const names=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d=>`<div class="calendar-day-name">${d}</div>`).join('');let cells='';for(let d=new Date(start);d<=end;d.setDate(d.getDate()+1)){const key=dateKey(d);const events=(byDate[key]||[]);cells+=`<div class="calendar-day ${d.getMonth()===month.getMonth()?'':'out'}"><div class="calendar-date">${d.getDate()}</div>${events.map(e=>e.kind==='booking'?`<button class="calendar-event ${bookingTone(e.item.status)}" type="button" data-calendar-booking="${esc(e.item.id)}">${esc(e.item.startTime||'Time TBD')} ${esc(e.item.boatName||e.item.boatId)}<span>${esc(e.item.customerName||'Guest')} | ${esc(e.item.status||'requested')}</span></button>`:`<button class="calendar-event ${e.item.entityType==='captain'?'captain-block':'bad'}" type="button" data-calendar-availability="${esc(e.item.id)}">${e.item.entityType==='captain'?'Captain':'Boat'}: ${esc(availabilityLabel(e.item))}<span>${esc(e.item.startAt.slice(11,16))}-${esc(e.item.endAt.slice(11,16))} ${esc(e.item.notes||e.item.status||'')}</span></button>`).join('')}</div>`;}bookingCalendar.innerHTML=names+cells;bookingCalendar.querySelectorAll('[data-calendar-booking]').forEach(btn=>btn.onclick=()=>focusBookingCard(btn.dataset.calendarBooking));bookingCalendar.querySelectorAll('[data-calendar-availability]').forEach(btn=>btn.onclick=()=>deleteAvailabilityBlock(btn.dataset.calendarAvailability));}
    function focusBookingCard(id){selectBooking(id);}
    function bookingTone(status){return ['confirmed','completed','approved'].includes(status)?'good':['requested','declined','cancelled'].includes(status)?'bad':'';}
    function bookingStatusOptions(current){return bookingStatuses.includes(current)||current==='booked'?bookingStatuses:[current,...bookingStatuses].filter(Boolean);}
    function kanbanBucket(b){const agreement=agreementStatus(b);if(['declined','cancelled','completed'].includes(b.status))return 'closed';if(b.status==='requested')return 'requested';if(b.status==='reviewing')return 'reviewing';if(agreement==='signed')return 'signed';if(agreement==='sent')return 'sent';if(['confirmed','completed'].includes(b.status))return 'packet';return 'reviewing';}
    function renderBookingKanban(){if(!window.bookingKanban)return;const columns=[['requested','New Requests'],['reviewing','Needs Follow-up'],['packet','Packet Needed'],['sent','Packet Sent'],['signed','Signed / Ready'],['closed','Completed / Closed']];const sorted=[...state.bookings].sort((a,b)=>String(a.charterDate||a.createdAt||'').localeCompare(String(b.charterDate||b.createdAt||'')));bookingKanban.innerHTML=columns.map(([key,label])=>{const items=sorted.filter(b=>kanbanBucket(b)===key);return `<section class="kanban-column"><div class="kanban-column-head"><h3>${esc(label)}</h3><span>${items.length}</span></div><div class="kanban-list">${items.slice(0,8).map(b=>`<button class="kanban-card" type="button" data-kanban-booking="${esc(b.id)}"><strong>${esc(b.customerName||'Guest')}</strong><span>${esc(b.boatName||b.boatId||'Boat TBD')}</span><small>${esc(b.charterDate||'Date TBD')} ${esc(b.startTime||'')} | ${esc(agreementStatus(b))}</small></button>`).join('')||'<div class="kanban-empty">No bookings</div>'}${items.length>8?`<p class="muted">${items.length-8} more in Bookings</p>`:''}</div></section>`}).join('');bookingKanban.querySelectorAll('[data-kanban-booking]').forEach(card=>card.onclick=()=>{go('bookings');selectBooking(card.dataset.kanbanBooking);});}
    function approvedCaptainsForBooking(b){const boat=state.boats.find(x=>x.id===b.boatId);const approvedIds=boat?.approvedCaptainIds||[];const list=approvedIds.length?approvedIds.map(id=>state.captains.find(c=>c.id===id)).filter(Boolean):state.captains;return b.captainId&&!list.some(c=>c.id===b.captainId)?[...list,state.captains.find(c=>c.id===b.captainId)].filter(Boolean):list;}
    function bookingDraft(id){const read=suffix=>bookingList.querySelector(`[data-booking-${suffix}="${CSS.escape(id)}"]`);const current=state.bookings.find(b=>b.id===id)||{};snapHalfHour(read('time'));return {status:read('status')?.value||'requested',captainId:read('captain')?.value||null,charterDate:read('date')?.value||null,startTime:read('time')?.value||null,durationHours:Number(read('duration')?.value||4),officeNotes:read('notes')?.value||'',agreementStatus:agreementStatus(current),signingUrl:current.signingUrl||''};}
    function additionalChargeItems(id){return [...bookingList.querySelectorAll(`[data-additional-row="${CSS.escape(id)}"]`)].map(row=>({description:row.querySelector('[data-additional-desc]')?.value.trim()||'',amount:num(row.querySelector('[data-additional-amount]')?.value,0)})).filter(item=>item.description||item.amount);}
    function additionalChargeRow(id,item={}){return `<div class="additional-charge-row" data-additional-row="${esc(id)}"><input data-additional-desc placeholder="Description" value="${esc(item.description||'')}"><input data-additional-amount type="number" min="0" step="0.01" placeholder="Amount" value="${item.amount!==undefined?Number(item.amount):''}"><button class="btn danger" type="button" data-remove-additional="${esc(id)}">Remove</button></div>`;}
    function rememberSettlementDraft(id){if(!id)return;state.settlementDrafts[id]=closeoutDraft(id);state.lastSettlementEditAt=Date.now();}
    function addAdditionalChargeRow(id,item={}){const rows=bookingList.querySelector(`[data-additional-rows="${CSS.escape(id)}"]`);if(!rows)return;rows.insertAdjacentHTML('beforeend',additionalChargeRow(id,item));bindSettlementInputs();rememberSettlementDraft(id);updateSettlementPreview(id);}
    function closeoutDraft(id){const read=suffix=>bookingList.querySelector(`[data-closeout-${suffix}="${CSS.escape(id)}"]`);const items=additionalChargeItems(id);const miles=num(read('miles')?.value,0);return {actualHours:Number(read('hours')?.value||0),paymentStatus:read('payment')?.value||'unsettled',notes:read('notes')?.value||'',milesTraveled:miles,billableMiles:miles,mileageRate:num(read('mileage-rate')?.value,settingNumber('mileage_rate',14)),fuelAmount:0,fuelPaidBy:'',cleaningFeeCharged:read('cleaning')?.value==='yes',additionalChargeItems:items,additionalCharges:items.reduce((sum,item)=>sum+num(item.amount,0),0),captainHourlyRate:num(read('captain-rate')?.value,settingNumber('captain_hourly_rate',125)),ownerSplit:num(read('owner-split')?.value,settingNumber('owner_split',0.85)),coveSplit:num(read('cove-split')?.value,settingNumber('cove_split',0.15)),officeStatus:'draft'};}
    function num(value,fallback=0){if(value===null||value===undefined||value==='')return fallback;const n=Number(value);return Number.isFinite(n)?n:fallback;}
    function money2(value){return new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:2}).format(Number(value||0));}
    function settingNumber(key,fallback){const n=Number(state.settings[key]);return Number.isFinite(n)?n:fallback;}
    function payoutMath(b,d=closeoutDraft(b.id)){const billable=num(d.milesTraveled??d.billableMiles,0);const mileageCharge=billable*d.mileageRate;const base=Number(b.baseFee||0);const cleaning=d.cleaningFeeCharged?Number(b.cleaningFee||settingNumber('cleaning_fee',0)):0;const tax=(base+cleaning)*Number(b.taxRate||settingNumber('sales_tax_rate',0));const fuelDeposit=Number(b.fuelDeposit||settingNumber('fuel_deposit',0));const captainPay=(d.actualHours||Number(b.durationHours||0))*d.captainHourlyRate;const net=Math.max(0,base-captainPay);const ownerPayout=net*d.ownerSplit;const coveCommission=net*d.coveSplit;const fuelRefund=Math.max(0,fuelDeposit-mileageCharge-d.additionalCharges);const grossRevenue=base+cleaning+tax+fuelDeposit+mileageCharge+d.additionalCharges;const grossProfit=coveCommission;return {billableMiles:billable,milesTraveled:billable,mileageCharge,cleaningFee:cleaning,taxCollected:tax,fuelDeposit,fuelDepositRefund:fuelRefund,captainPay,ownerPayout,coveCommission,grossRevenue,grossProfit};}
    function stampNote(existing,line){const stamp=`[${new Date().toLocaleString()}] ${line}`;return [existing,stamp].filter(Boolean).join('\n');}
    function captainPacketReady(b){return ['confirmed','completed'].includes(b.status)&&Boolean(b.captainId);}
    function customerReply(b,type='confirm'){const d=bookingDraft(b.id);const boat=b.boatName||b.boatId||'your charter';const date=d.charterDate||b.charterDate||'the requested date';const start=d.startTime||b.startTime||'the requested time';const captain=state.captains.find(c=>c.id===d.captainId)?.name||b.captainName||'your captain';if(type==='decline')return `Hi ${b.customerName||'there'}, thanks for reaching out to Cove Charters. We are sorry, but ${boat} is not available for ${date} at ${start}. We would be happy to help find another option.`;return `Hi ${b.customerName||'there'}, thanks for your Cove Charters request. We can confirm ${boat} for ${date} at ${start} for ${Number(d.durationHours||b.durationHours||4)} hours. ${captain} is currently assigned. Please reply here with any questions or changes.`;}
    function agreementPacket(b){const d=bookingDraft(b.id);const captain=state.captains.find(c=>c.id===d.captainId)?.name||b.captainName||'Captain TBD';return [`Cove Charters agreement packet`,`Booking: ${b.id}`,`Customer: ${b.customerName||'Guest'}`,`Email: ${b.email||'Not provided'}`,`Phone: ${b.phone||'Not provided'}`,`Boat: ${b.boatName||b.boatId}`,`Captain selected by customer: ${captain}`,`Charter date/time: ${d.charterDate||b.charterDate||'Date TBD'} ${d.startTime||b.startTime||''}`,`Duration: ${Number(d.durationHours||b.durationHours||0)} hours`,'',`Bareboat note: customer must independently select and approve their captain from the boat-approved captain list. Cove should not assign the captain on the customer's behalf.`,'',`Checklist:`,`- Confirm customer identity and contact details`,`- Confirm boat, date, start time, and duration`,`- Confirm customer captain selection`,`- Send bareboat charter agreement`,`- Collect signed agreement before trip`,`- Confirm payment/deposit status`,`- Attach agreement copy for back office and captain`].join('\n');}
    function captainPacket(b){const d=bookingDraft(b.id);const captain=state.captains.find(c=>c.id===d.captainId)||{};const conflicts=conflictsForBooking({...b,captainId:d.captainId,charterDate:d.charterDate,startTime:d.startTime,durationHours:d.durationHours});return [`Cove captain trip packet`,`Booking: ${b.id}`,`Captain: ${captain.name||b.captainName||'Captain TBD'}`,`Captain email: ${captain.email||b.captainEmail||'Not provided'}`,`Captain phone: ${captain.phone||b.captainPhone||'Not provided'}`,'',`Boat: ${b.boatName||b.boatId}`,`Date/time: ${d.charterDate||b.charterDate||'Date TBD'} ${d.startTime||b.startTime||''}`,`Duration: ${Number(d.durationHours||b.durationHours||0)} hours`,`Agreement status: ${d.agreementStatus}`,'',`Customer: ${b.customerName||'Guest'}`,`Customer phone: ${b.phone||'Not provided'}`,`Customer email: ${b.email||'Not provided'}`,'',`Customer notes: ${b.customerNotes||'None'}`,`Office notes: ${d.officeNotes||b.officeNotes||'None'}`,`Availability warnings: ${conflicts.length?conflicts.map(availabilityLabel).join('; '):'None'}`].join('\n');}
    function settlementSummary(b){const d=bookingDraft(b.id);const closeout=closeoutDraft(b.id);const calc=payoutMath(b,closeout);const charges=closeout.additionalChargeItems.length?closeout.additionalChargeItems.map(item=>`Additional charge - ${item.description||'Untitled'}: ${money2(item.amount)}`):['Additional charges: $0.00'];return [`Cove settlement summary`,`Booking: ${b.id}`,`Status: ${d.status}`,`Customer: ${b.customerName||'Guest'}`,`Boat: ${b.boatName||b.boatId}`,`Captain: ${state.captains.find(c=>c.id===d.captainId)?.name||b.captainName||'Captain TBD'}`,`Scheduled: ${d.charterDate||b.charterDate||'Date TBD'} ${d.startTime||b.startTime||''}`,`Scheduled hours: ${Number(d.durationHours||b.durationHours||0)}`,`Actual hours: ${closeout.actualHours||Number(d.durationHours||b.durationHours||0)}`,`Miles traveled: ${calc.milesTraveled}`,`Fuel charge: ${money2(calc.mileageCharge)}`,...charges,`Captain pay: ${money2(calc.captainPay)}`,`Owner payout: ${money2(calc.ownerPayout)}`,`Cove commission: ${money2(calc.coveCommission)}`,`Fuel deposit refund: ${money2(calc.fuelDepositRefund)}`,`Gross revenue: ${money2(calc.grossRevenue)}`,`Gross profit: ${money2(calc.grossProfit)}`,`Payment status: ${closeout.paymentStatus}`,`Agreement status: ${d.agreementStatus}`,`Closeout notes: ${closeout.notes||'None'}`,`Office notes: ${d.officeNotes||b.officeNotes||'None'}`].join('\n');}
    function finalInvoiceText(b){const d=bookingDraft(b.id);const closeout=closeoutDraft(b.id);const calc=payoutMath(b,closeout);const charges=closeout.additionalChargeItems.map(item=>`${item.description||'Additional charge'}: ${money2(item.amount)}`);const net=Number(b.baseFee||0)+calc.cleaningFee+calc.taxCollected+calc.mileageCharge+closeout.additionalCharges;return [`Hi ${b.customerName||'there'},`,``,`Thank you for choosing Cove Charters. Here is the final invoice summary for your charter.`,``,`Booking: ${b.id}`,`Boat: ${b.boatName||b.boatId}`,`Date: ${d.charterDate||b.charterDate||'TBD'}`,`Start time: ${d.startTime||b.startTime||'TBD'}`,`Duration: ${Number(d.durationHours||b.durationHours||0)} hours`,`Captain: ${state.captains.find(c=>c.id===d.captainId)?.name||b.captainName||'Captain TBD'}`,``,`Charter fee: ${money2(b.baseFee||0)}`,`Cleaning fee: ${money2(calc.cleaningFee)}`,`Sales tax: ${money2(calc.taxCollected)}`,`Fuel charge (${calc.milesTraveled} miles): ${money2(calc.mileageCharge)}`,...charges,``,`Fuel deposit collected: ${money2(calc.fuelDeposit)}`,`Net final charges: ${money2(net)}`,`Fuel deposit refund / credit: ${money2(calc.fuelDepositRefund)}`,`Payment status: ${closeout.paymentStatus}`,``,`Please reply to this email with any questions. If a balance or refund remains, Cove will coordinate the next step.`].join('\n');}
    function agreementStatusFromNotes(b){const matches=[...String(b.officeNotes||'').matchAll(/Agreement status: ([^\n]+)/g)];return matches.length?matches.at(-1)[1].trim():'not started';}
    function agreementStatus(b){return b.agreementStatus||agreementStatusFromNotes(b);}
    function agreementTone(status){return status==='signed'?'good':status==='not started'?'bad':'';}
    function agreementIndicator(b){const status=agreementStatus(b);const tone=agreementTone(status);return `<span class="badge agreement-indicator ${tone}">Agreement ${esc(status)}</span>`;}
    function bookingActionGroups(b){const status=b.status==='booked'?'confirmed':b.status;const active=['confirmed','completed'].includes(status);const canCaptain=captainPacketReady(b);const disabled=active?'':'disabled';const bookingCta=active?`<button class="btn light" type="button" data-send-agreement="${esc(b.id)}">Resend Agreement</button>`:`<button class="btn sand" type="button" data-confirm-booking="${esc(b.id)}">Confirm & Send Packet</button>`;const stopAction=status==='confirmed'?`<button class="btn danger" type="button" data-cancel-booking="${esc(b.id)}">Cancel</button>`:(!active?`<button class="btn danger" type="button" data-decline-booking="${esc(b.id)}">Decline</button>`:'');return `<div class="booking-actions"><section class="booking-action-group primary"><span class="booking-action-label">Booking</span>${bookingCta}${stopAction}</section><section class="booking-action-group customer"><span class="booking-action-label">Customer</span><button class="btn sand" type="button" data-send-final-invoice="${esc(b.id)}" ${disabled}>Send Final Invoice</button><button class="btn light" type="button" data-send-confirmation="${esc(b.id)}" ${disabled}>Send Confirmation Only</button></section><section class="booking-action-group ops"><span class="booking-action-label">Internal</span><button class="btn light" type="button" data-copy-captain-trip="${esc(b.id)}" ${canCaptain?'':'disabled'}>Copy Captain Link</button><button class="btn sand" type="button" data-send-captain="${esc(b.id)}" ${canCaptain?'':'disabled'}>Send Captain Packet</button><button class="btn sand" type="button" data-complete-trip="${esc(b.id)}" ${disabled}>Complete Trip</button></section></div>`;}
    function documentPanel(b){const docs=b.documents||[];const signatures=b.signatures||[];const signedRecord=docs.find(doc=>doc.documentType==='electronic_signature_record'&&doc.url);const signingActions=b.signingUrl?`<button class="btn light" type="button" data-copy-signing="${esc(b.id)}">Copy signing link</button>`:'<span class="muted">No signing link generated yet.</span>';const links=docs.length?docs.map(doc=>`<a class="btn light" href="${esc(doc.url)}" target="_blank" rel="noopener">${doc.documentType==='electronic_signature_record'?'Open signed packet':`Open ${esc(doc.title||doc.documentType||'document')}`}</a>`).join(''):'<span class="muted">No uploaded documents attached.</span>';const sigs=signatures.length?signatures.map(sig=>`<a class="pill" href="${esc(signedRecord?.url||b.signingUrl||'#')}" target="_blank" rel="noopener">Signed by ${esc(sig.signerName)} ${esc(sig.signedAt||'')}</a>`).join(''):'<span class="pill">No electronic signature yet</span>';return `<div class="panel booking-subpanel document-panel"><div class="panel-head"><h2>Documents</h2></div><div class="panel-body"><div class="document-action-row">${signingActions}<input class="hidden" type="file" multiple accept=".pdf,.doc,.docx,.xls,.xlsx,.csv,.txt,.rtf,.jpg,.jpeg,.png,.webp,image/jpeg,image/png,image/webp,application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet,text/plain,text/csv,application/rtf" data-doc-files="${esc(b.id)}"><button class="btn light" type="button" data-pick-documents="${esc(b.id)}">Attach Files</button></div><div class="document-link-row">${links}</div><div class="pill-row">${sigs}</div></div></div>`;}
    function accountingRecordsPanel(b){const rows=b.accountingRecords||[];const body=rows.length?rows.map(r=>`<div class="accounting-row"><span>${esc(r.partyType||'party')}</span><strong>${esc(r.label||r.category)}</strong><span class="${r.direction==='credit'?'credit':'debit'}">${esc(r.direction||'')}</span><strong>${money2(r.amount)}</strong><span>${esc(r.status||'draft')}</span></div>`).join(''):'<p class="muted">Save the settlement to generate structured accounting records.</p>';return `<details class="accounting-records"><summary><strong>Accounting records</strong><span class="muted">${rows.length} saved row(s)</span></summary><div class="accounting-record-list">${body}</div></details>`;}
    function accountingRows(){return state.bookings.flatMap(b=>(b.accountingRecords||[]).map(r=>({...r,bookingId:b.id,customerName:b.customerName||'Guest',boatName:b.boatName||b.boatId||'Boat TBD',charterDate:b.charterDate||'',status:b.status||''})));}
    function sumRows(rows,filter){return rows.filter(filter).reduce((sum,r)=>sum+Number(r.amount||0),0);}
    function reportGroup(rows,keyFn){const totals=new Map();rows.forEach(r=>{const key=keyFn(r);totals.set(key,(totals.get(key)||0)+Number(r.amount||0));});return [...totals.entries()].sort((a,b)=>Math.abs(b[1])-Math.abs(a[1]));}
    function renderReporting(){const rows=accountingRows();const customerCharges=sumRows(rows,r=>r.partyType==='customer'&&r.direction==='debit');const captainPay=sumRows(rows,r=>r.category==='captain_payout');const ownerPayout=sumRows(rows,r=>r.category==='owner_payout');const coveCommission=sumRows(rows,r=>r.category==='cove_commission');reportRows.textContent=rows.length;reportCustomerCharges.textContent=money(customerCharges);reportCaptainPay.textContent=money(captainPay);reportOwnerPayout.textContent=money(ownerPayout);reportCoveCommission.textContent=money(coveCommission);const groups=[['By party',reportGroup(rows,r=>r.partyType||'unknown')],['By category',reportGroup(rows,r=>(r.category||'uncategorized').replaceAll('_',' '))],['By status',reportGroup(rows,r=>r.status||'draft')]];reportingTotals.innerHTML=groups.map(([title,items])=>`<section class="reporting-card"><h3>${esc(title)}</h3>${items.length?items.map(([label,total])=>`<div><span>${esc(label)}</span><strong>${money2(total)}</strong></div>`).join(''):'<p class="muted">No accounting rows yet.</p>'}</section>`).join('');reportingRows.innerHTML=rows.length?rows.map(r=>`<article class="reporting-row"><span>${esc(r.charterDate||'No date')}</span><strong>${esc(r.customerName)}</strong><span>${esc(r.boatName)}</span><span>${esc(r.partyType)} / ${esc((r.category||'').replaceAll('_',' '))}</span><span class="${r.direction==='credit'?'credit':'debit'}">${esc(r.direction)}</span><strong>${money2(r.amount)}</strong></article>`).join(''):'<div class="item">No accounting records yet. Save a booking settlement to generate reportable rows.</div>';reportingStatus.textContent=`${rows.length} accounting row(s) across ${new Set(rows.map(r=>r.bookingId)).size} booking(s).`;}
    function settlementPanel(b){const t=b.trip||{},s=b.settlement||{},draft=state.settlementDrafts[b.id]||{};const actual=draft.actualHours??s.actualHours??t.actualHours??b.durationHours??4;const miles=draft.milesTraveled??t.billableMiles??s.milesTraveled??'';const rate=draft.mileageRate??t.mileageRate??b.mileageRate??settingNumber('mileage_rate',14);const captainRate=draft.captainHourlyRate??s.captainHourlyRate??settingNumber('captain_hourly_rate',125);const ownerSplit=draft.ownerSplit??s.ownerSplit??settingNumber('owner_split',0.85);const coveSplit=draft.coveSplit??s.coveSplit??settingNumber('cove_split',0.15);const existingItems=Array.isArray(draft.additionalChargeItems)&&draft.additionalChargeItems.length?draft.additionalChargeItems:Array.isArray(s.additionalChargeItems)&&s.additionalChargeItems.length?s.additionalChargeItems:(Number(s.additionalCharges||0)>0?[{description:'Additional charge',amount:s.additionalCharges}]:[{description:'',amount:''}]);const clean=draft.cleaningFeeCharged!==undefined?(draft.cleaningFeeCharged?'yes':'no'):(s.cleaningFee>0||t.cleaningFeeCharged||(!b.trip&&!b.settlement)?'yes':'no');const paid=draft.paymentStatus||s.customerPaidStatus||b.paidStatus||'unsettled';const notes=draft.notes??s.notes??t.officeNotes??'';return `<div class="panel booking-subpanel settlement-panel"><div class="panel-head"><h2>Settlement calculator</h2></div><div class="panel-body"><div class="booking-grid"><label>Actual hours<input type="number" min="0" step="0.5" data-closeout-hours="${esc(b.id)}" value="${Number(actual)}"></label><label>Miles traveled<input type="number" min="0" step="0.1" data-closeout-miles="${esc(b.id)}" value="${esc(miles)}"></label><label>Fuel rate / mile<input type="number" min="0" step="0.01" data-closeout-mileage-rate="${esc(b.id)}" value="${Number(rate)}"></label><label>Cleaning charged<select data-closeout-cleaning="${esc(b.id)}"><option value="no" ${clean==='no'?'selected':''}>no</option><option value="yes" ${clean==='yes'?'selected':''}>yes</option></select></label><div class="full additional-charges"><div class="additional-charges-head"><strong>Additional charges</strong><button class="btn light" type="button" data-add-additional="${esc(b.id)}">Add Line Item</button></div><div class="additional-charge-list" data-additional-rows="${esc(b.id)}">${existingItems.map(item=>additionalChargeRow(b.id,item)).join('')}</div></div><label>Captain rate<input type="number" min="0" step="0.01" data-closeout-captain-rate="${esc(b.id)}" value="${Number(captainRate)}"></label><label>Owner split<input type="number" min="0" max="1" step="0.01" data-closeout-owner-split="${esc(b.id)}" value="${Number(ownerSplit)}"></label><label>Cove split<input type="number" min="0" max="1" step="0.01" data-closeout-cove-split="${esc(b.id)}" value="${Number(coveSplit)}"></label><label>Payment<select data-closeout-payment="${esc(b.id)}"><option value="unsettled" ${paid==='unsettled'||paid==='unpaid'?'selected':''}>unsettled</option><option value="deposit paid" ${paid==='deposit paid'?'selected':''}>deposit paid</option><option value="paid in full" ${paid==='paid in full'?'selected':''}>paid in full</option><option value="needs review" ${paid==='needs review'?'selected':''}>needs review</option></select></label><label class="wide">Closeout notes<input data-closeout-notes="${esc(b.id)}" value="${esc(notes)}" placeholder="Fuel charge, cleaning, damage, payout notes..."></label></div><div class="settlement-preview" data-settlement-preview="${esc(b.id)}"></div>${accountingRecordsPanel(b)}</div></div>`;}
    function customerKeyFromBooking(b){return (b.email||b.phone||b.customerId||b.customerName||b.id||'customer').toLowerCase().replace(/[^a-z0-9@.+-]+/g,'-');}
    function customerStatusFor(customer){return ['vip','banned'].includes(customer.status)?customer.status:(customer.status==='repeat'||customer.bookings.length>1||Number(customer.bookingCount||0)>1?'repeat':'new');}
    async function loadCustomers(){try{const r=await fetch(`${api()}/api/v1/customers`,{headers:adminHeaders(),cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load customers');state.customerRecords=d.map(c=>({...c,bookings:[]}));if(document.getElementById('customers')?.classList.contains('active'))renderCustomers();}catch(e){console.warn('Cove customers unavailable',e);if(document.getElementById('customers')?.classList.contains('active'))customerList.innerHTML=`<div class="item">Could not load customers: ${esc(e.message)}</div>`;}}
    function deriveCustomers(){const byKey={};state.customerRecords.forEach(c=>{byKey[c.id]={...c,bookings:[]};});state.bookings.forEach(b=>{const existing=byKey[b.customerId]||Object.values(byKey).find(c=>(b.email&&c.email&&b.email.toLowerCase()===c.email.toLowerCase())||(b.phone&&c.phone&&b.phone===c.phone));const key=existing?.id||customerKeyFromBooking(b);const cur=byKey[key]||{id:key,name:b.customerName||'Guest',email:b.email||'',phone:b.phone||'',bookings:[],favoriteBoat:'',favoriteCaptain:'',notes:'',status:'new',derived:true};cur.name=cur.name||b.customerName||'Guest';cur.email=cur.email||b.email||'';cur.phone=cur.phone||b.phone||'';cur.bookings.push(b);byKey[key]=cur;});state.customers=Object.values(byKey).map(c=>{const recent=[...(c.bookings||[])].sort((a,b)=>String(b.charterDate||b.createdAt||'').localeCompare(String(a.charterDate||a.createdAt||'')));return {...c,bookings:recent,favoriteBoat:c.favoriteBoat||c.lastBoatName||recent[0]?.boatName||recent[0]?.boatId||'',favoriteCaptain:c.favoriteCaptain||c.lastCaptainName||recent[0]?.captainName||'',status:customerStatusFor({...c,bookings:recent}),notes:c.notes||recent[0]?.customerNotes||''};}).sort((a,b)=>String(a.name||'').localeCompare(String(b.name||'')));}
    function showCustomerList(){state.selectedCustomerId=null;customerListScreen.classList.remove('hidden');customerDetailScreen.classList.add('hidden');renderCustomers();}
    function renderCustomers(){deriveCustomers();const q=(customerSearch?.value||'').trim().toLowerCase();const rows=state.customers.filter(c=>[c.name,c.email,c.phone,c.status,c.favoriteBoat,c.favoriteCaptain,c.notes,...c.bookings.map(b=>`${b.boatName||''} ${b.captainName||''} ${b.customerNotes||''}`)].join(' ').toLowerCase().includes(q));customerStatTotal.textContent=state.customers.length;customerStatRepeat.textContent=state.customers.filter(c=>c.status==='repeat').length;customerStatVip.textContent=state.customers.filter(c=>c.status==='vip').length;customerStatBanned.textContent=state.customers.filter(c=>c.status==='banned').length;customerList.innerHTML=rows.map(c=>{const count=c.bookings.length||Number(c.bookingCount||0);return `<article class="item click" data-customer-id="${esc(c.id)}"><div class="item-top"><div><h3>${esc(c.name||'Guest')}</h3><p>${esc(c.phone||'No phone')} | ${esc(c.email||'No email')}</p></div><span class="badge ${c.status==='banned'?'banned':c.status==='vip'?'good':c.status==='new'?'bad':''}">${esc(c.status)}</span></div><div class="pill-row"><span class="pill">${count} booking${count===1?'':'s'}</span><span class="pill">${esc(c.favoriteBoat||'Boat TBD')}</span><span class="pill">${esc(c.favoriteCaptain||'Captain TBD')}</span></div></article>`}).join('')||'<div class="empty-media">No customers match that search.</div>';customerList.querySelectorAll('[data-customer-id]').forEach(item=>item.onclick=()=>selectCustomer(item.dataset.customerId));}
    function selectCustomer(id){deriveCustomers();const c=state.customers.find(x=>x.id===id);if(!c)return;const count=c.bookings.length||Number(c.bookingCount||0);state.selectedCustomerId=id;customerListScreen.classList.add('hidden');customerDetailScreen.classList.remove('hidden');customerBreadcrumbName.textContent=c.name||'Customer';customerDetailTitle.textContent=c.name||'Customer Details';customerDetailSummary.textContent=`${c.phone||'No phone'} | ${c.email||'No email'} | ${count} booking${count===1?'':'s'}`;customerDetailStatus.textContent=c.status;customerDetailStatus.className=`badge ${c.status==='banned'?'banned':c.status==='vip'?'good':c.status==='new'?'bad':''}`;customerBannedBanner.classList.toggle('show',c.status==='banned');customerDetailPills.innerHTML=[c.favoriteBoat||'Boat TBD',c.favoriteCaptain||'Captain TBD',`${count} booking${count===1?'':'s'}`].map(x=>`<span class="pill">${esc(x)}</span>`).join('');customerName.value=c.name||'';customerStatus.value=c.status||'new';customerEmail.value=c.email||'';customerPhone.value=c.phone||'';customerFavoriteBoat.value=c.favoriteBoat||'';customerFavoriteCaptain.value=c.favoriteCaptain||'';customerNotes.value=c.notes||'';customerHistory.innerHTML=c.bookings.length?c.bookings.map(b=>`<div class="timeline-entry"><strong>${esc(b.charterDate||b.createdAt||'Date TBD')}</strong><span>${esc(b.boatName||b.boatId||'Boat')} | ${esc(b.captainName||'Captain TBD')} | ${esc(b.status||'requested')}</span></div>`).join(''):'<div class="empty-media">No charter history yet.</div>';scrollTo({top:0,behavior:'smooth'});}
    async function saveCustomer(){if(!state.selectedCustomerId)return;setButtonsBusy(['saveCustomerCompact'],true);showAdminSaveStatus('saveCustomerCompact','customerSaveStatus','Saving customer...','info');try{const c=state.customers.find(x=>x.id===state.selectedCustomerId)||{};const payload={id:c.derived?null:state.selectedCustomerId,name:customerName.value,status:customerStatus.value,email:customerEmail.value,phone:customerPhone.value,favoriteBoat:customerFavoriteBoat.value,favoriteCaptain:customerFavoriteCaptain.value,notes:customerNotes.value};const url=payload.id?`${api()}/api/v1/customers/${encodeURIComponent(payload.id)}`:`${api()}/api/v1/customers`;const r=await fetch(url,{method:payload.id?'PUT':'POST',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(payload)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not save customer');await loadCustomers();selectCustomer(payload.id||d.id);showAdminSaveStatus('saveCustomerCompact','customerSaveStatus','Customer saved to D1.');}catch(e){showAdminSaveStatus('saveCustomerCompact','customerSaveStatus',e.message||'Could not save customer','bad');}finally{setButtonsBusy(['saveCustomerCompact'],false);}}
    async function createCustomer(){try{const r=await fetch(`${api()}/api/v1/customers`,{method:'POST',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({name:'New Customer',status:'new',email:'',phone:'',favoriteBoat:'',favoriteCaptain:'',notes:''})});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not create customer');await loadCustomers();selectCustomer(d.id);}catch(e){alert(e.message||'Could not create customer');}}
    function bookingSummary(b){const d=bookingDraft(b.id);return [`Cove booking request: ${b.id}`,`Customer: ${b.customerName||'Guest'}`,`Phone: ${b.phone||'Not provided'}`,`Email: ${b.email||'Not provided'}`,`Boat: ${b.boatName||b.boatId}`,`Captain: ${state.captains.find(c=>c.id===d.captainId)?.name||b.captainName||'Captain TBD'}`,`Date/time: ${d.charterDate||b.charterDate||'Date TBD'} ${d.startTime||b.startTime||''}`,`Duration: ${Number(d.durationHours||b.durationHours||0)} hours`,`Status: ${d.status||b.status}`,`Customer notes: ${b.customerNotes||'None'}`,`Office notes: ${d.officeNotes||b.officeNotes||'None'}`].join('\n');}
    function bookingEditorCard(b){const captains=approvedCaptainsForBooking(b);const conflicts=conflictsForBooking(b);const warningNotes=possibleConflictNotes(b);const conflictLines=conflicts.length?conflicts.map(a=>`${esc(a.status)}: ${esc(availabilityLabel(a))} ${esc(a.startAt)} to ${esc(a.endAt)}`):warningNotes.map(esc);const emailContact=b.email?`<a href="mailto:${esc(b.email)}">${esc(b.email)}</a>`:'<strong>No email</strong>';const phoneContact=b.phone?`<strong>${esc(b.phone)}</strong>`:'<strong>No phone</strong>';const settlementMarkup=['confirmed','completed'].includes(b.status)?settlementPanel(b):'';const selectedStatus=b.status==='booked'?'confirmed':b.status;return `<article class="item booking-card" id="booking-${esc(b.id)}" data-booking-card="${esc(b.id)}"><div class="item-top"><div><h3>${esc(b.customerName||'Guest')}</h3><div class="booking-contact-row"><span class="booking-contact-item"><span>Email</span>${emailContact}</span><span class="booking-contact-item"><span>Phone</span>${phoneContact}</span></div><p class="booking-trip-line">${esc(b.boatName||b.boatId)} | ${esc(b.charterDate||'Date TBD')} ${esc(b.startTime||'')}</p></div><span class="badge ${bookingTone(b.status)}">${esc(bookingStatusLabel(b.status))}</span></div><div class="pill-row"><span class="pill">${esc(b.captainName||'Captain TBD')}</span><span class="pill">${Number(b.durationHours||0)} hours</span>${agreementIndicator(b)}</div>${conflictLines.length?`<div class="conflict-warning"><strong>Possible Conflict</strong><p>${conflictLines.join('<br>')}</p></div>`:''}<div class="booking-section-title">Booking details</div><div class="booking-grid"><label>Status<select data-booking-status="${esc(b.id)}">${bookingStatusOptions(b.status).map(s=>`<option value="${s}" ${selectedStatus===s?'selected':''}>${esc(bookingStatusLabel(s))}</option>`).join('')}</select></label><label class="wide">Captain<select data-booking-captain="${esc(b.id)}"><option value="">Captain TBD</option>${captains.map(c=>`<option value="${esc(c.id)}" ${b.captainId===c.id?'selected':''}>${esc(c.name)}</option>`).join('')}</select></label><label>Date<input type="date" data-booking-date="${esc(b.id)}" value="${esc(b.charterDate||'')}"></label><label>Start time<input type="time" step="1800" list="halfHourTimes" data-booking-time="${esc(b.id)}" value="${esc(b.startTime||'')}"></label><label>Hours<input type="number" min="1" step="0.5" data-booking-duration="${esc(b.id)}" value="${Number(b.durationHours||4)}"></label></div><div class="booking-section-title">Notes</div><div class="booking-notes"><label>Customer notes<textarea readonly>${esc(b.customerNotes||'No customer notes yet.')}</textarea></label><label>Office notes<textarea data-booking-notes="${esc(b.id)}" placeholder="Availability checks, partner call notes, payment details...">${esc(b.officeNotes||'')}</textarea></label></div>${documentPanel(b)}${settlementMarkup}${bookingActionGroups(b)}<p class="muted copy-status" data-booking-copy-status="${esc(b.id)}"></p></article>`;}
    function renderBookingSummaryList(sorted){const target=document.getElementById('bookingSummaryList')||bookingList;target.innerHTML=sorted.map(b=>{const conflicts=conflictsForBooking(b).length||possibleConflictNotes(b).length;return `<article class="item click booking-summary-card" data-booking-summary="${esc(b.id)}"><div class="item-top"><div><h3>${esc(b.customerName||'Guest')}</h3><p>${esc(b.boatName||b.boatId)} | ${esc(b.charterDate||'Date TBD')} ${esc(b.startTime||'')}</p></div><span class="badge ${bookingTone(b.status)}">${esc(b.status)}</span></div><div class="pill-row"><span class="pill">${esc(b.email||'No email')}</span><span class="pill">${esc(b.phone||'No phone')}</span><span class="pill">${esc(b.captainName||'Captain TBD')}</span><span class="pill">${Number(b.durationHours||0)} hours</span>${agreementIndicator(b)}${conflicts?'<span class="pill warning">Possible conflict</span>':''}</div></article>`}).join('')||'<div class="item">No booking requests match these filters.</div>';target.querySelectorAll('[data-booking-summary]').forEach(card=>card.onclick=()=>selectBooking(card.dataset.bookingSummary));}
    function renderBookingDetail(b){if(!b){bookingList.innerHTML='<div class="item">Select a booking from the summary list.</div>';return;}bookingBreadcrumbName.textContent=b.customerName||'Booking Details';bookingDetailTitle.textContent=b.customerName||'Booking Details';bookingDetailSummary.textContent=`${b.boatName||b.boatId||'Boat TBD'} | ${b.charterDate||'Date TBD'} ${b.startTime||''}`;bookingDetailStatus.textContent=b.status||'booking';bookingDetailStatus.className=`badge ${bookingTone(b.status)}`;bookingDetailPills.innerHTML=[b.email||'No email',b.phone||'No phone',b.captainName||'Captain TBD',`${Number(b.durationHours||0)} hours`].map(x=>`<span class="pill">${esc(x)}</span>`).join('')+agreementIndicator(b);bookingList.innerHTML=bookingEditorCard(b);bindBookingActions();}
    function bindBookingActions(){bookingList.querySelectorAll('[data-save-booking]').forEach(btn=>btn.onclick=()=>saveBooking(btn.dataset.saveBooking).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-confirm-booking]').forEach(btn=>btn.onclick=()=>quickBookingAction(btn.dataset.confirmBooking,'confirm').catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-decline-booking]').forEach(btn=>btn.onclick=()=>quickBookingAction(btn.dataset.declineBooking,'decline').catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-cancel-booking]').forEach(btn=>btn.onclick=()=>quickBookingAction(btn.dataset.cancelBooking,'cancel').catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-copy-confirm]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copyConfirm,'confirm'));bookingList.querySelectorAll('[data-copy-signing]').forEach(btn=>btn.onclick=()=>copySigningLink(btn.dataset.copySigning));bookingList.querySelectorAll('[data-pick-documents]').forEach(btn=>btn.onclick=()=>bookingList.querySelector(`[data-doc-files="${CSS.escape(btn.dataset.pickDocuments)}"]`)?.click());bookingList.querySelectorAll('[data-doc-files]').forEach(input=>input.onchange=()=>addBookingDocument(input.dataset.docFiles).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-send-confirmation]').forEach(btn=>btn.onclick=()=>sendBookingConfirmation(btn.dataset.sendConfirmation).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-send-agreement]').forEach(btn=>btn.onclick=()=>sendAgreementPacket(btn.dataset.sendAgreement).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-copy-decline]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copyDecline,'decline'));bookingList.querySelectorAll('[data-copy-agreement]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copyAgreement,'agreement'));bookingList.querySelectorAll('[data-copy-captain]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copyCaptain,'captain'));bookingList.querySelectorAll('[data-copy-captain-trip]').forEach(btn=>btn.onclick=()=>copyCaptainTripLink(btn.dataset.copyCaptainTrip).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-send-captain]').forEach(btn=>btn.onclick=()=>sendCaptainPacket(btn.dataset.sendCaptain).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-copy-settlement]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copySettlement,'settlement'));bookingList.querySelectorAll('[data-send-final-invoice]').forEach(btn=>btn.onclick=()=>sendFinalInvoice(btn.dataset.sendFinalInvoice).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-complete-trip]').forEach(btn=>btn.onclick=()=>completeTrip(btn.dataset.completeTrip).catch(e=>alert(e.message)));bindHalfHourTimes(bookingList);bindSettlementInputs();}
    function renderBookings(){renderBookingFilters();const sorted=filteredBookings().sort((a,b)=>(a.status==='requested'?0:1)-(b.status==='requested'?0:1)||String(b.createdAt||'').localeCompare(String(a.createdAt||'')));renderCalendar(sorted);if(state.selectedBookingId&&!state.bookings.some(b=>b.id===state.selectedBookingId))state.selectedBookingId=null;renderBookingSummaryList(sorted);const selected=state.selectedBookingId?state.bookings.find(b=>b.id===state.selectedBookingId):null;if(selected){showBookingDetail();renderBookingDetail(selected);}else{bookingList.innerHTML='';document.getElementById('bookingListScreen')?.classList.remove('hidden');document.getElementById('bookingDetailScreen')?.classList.add('hidden');setBookingView(state.bookingView);}bookingLoadStatus.textContent=`${sorted.length} of ${state.bookings.length} booking request(s) shown`;updateBookingBadges();}
    function setBookingSaveBusy(id,busy){bookingList.querySelectorAll(`[data-save-booking="${CSS.escape(id)}"]`).forEach(btn=>{btn.disabled=busy;btn.textContent=busy?'Saving...':'Save Booking';});const compact=document.getElementById('saveBookingCompact');if(compact&&state.selectedBookingId===id){compact.disabled=busy;compact.textContent=busy?'Saving...':'Save Booking';}}
    function setAgreementSendBusy(id,busy){bookingList.querySelectorAll(`[data-send-agreement="${CSS.escape(id)}"]`).forEach(btn=>{btn.disabled=busy;btn.dataset.defaultText ||= btn.textContent;btn.textContent=busy?'Sending...':btn.dataset.defaultText;});}
    function setConfirmSendBusy(id,busy){bookingList.querySelectorAll(`[data-confirm-booking="${CSS.escape(id)}"]`).forEach(btn=>{btn.disabled=busy;btn.dataset.defaultText ||= btn.textContent;btn.textContent=busy?'Confirming...':btn.dataset.defaultText;});}
    function setCompleteTripBusy(id,busy){bookingList.querySelectorAll(`[data-complete-trip="${CSS.escape(id)}"]`).forEach(btn=>{btn.disabled=busy;btn.dataset.defaultText ||= btn.textContent;btn.textContent=busy?'Completing...':btn.dataset.defaultText;});}
    function showBookingStatus(id,message,tone='good',options={}){const el=bookingList.querySelector(`[data-booking-copy-status="${CSS.escape(id)}"]`);if(!el)return;el.textContent=message;el.setAttribute('role','status');el.setAttribute('aria-live','polite');el.classList.add('show');el.classList.toggle('good',tone==='good');el.classList.toggle('bad',tone==='bad');el.classList.toggle('info',tone==='info');if(options.scroll)el.scrollIntoView({behavior:'smooth',block:'center'});}
    function cancellationReason(id){const reason=prompt('Cancellation reason required. This will be saved to the booking and customer record.');const clean=(reason||'').trim();if(!clean){showBookingStatus(id,'Cancellation reason is required before saving cancelled status.','bad',{scroll:true});return '';}return clean;}
    async function copyBookingText(id,type){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;const text=type==='summary'?bookingSummary(booking):type==='agreement'?agreementPacket(booking):type==='captain'?captainPacket(booking):type==='settlement'?settlementSummary(booking):customerReply(booking,type);await navigator.clipboard.writeText(text);showBookingStatus(id,`Copied ${type==='summary'?'internal summary':type} message.`);}
    async function copySigningLink(id){const booking=state.bookings.find(b=>b.id===id);if(!booking?.signingUrl){showBookingStatus(id,'No signing link has been generated yet.','bad');return;}await navigator.clipboard.writeText(booking.signingUrl);showBookingStatus(id,'Signing link copied.');}
    async function copyCaptainTripLink(id){showBookingStatus(id,'Creating captain trip link...','info');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/captain-trip-link`,{method:'POST',headers:adminHeaders()});const d=await r.json();if(!r.ok){showBookingStatus(id,d.error||'Could not create captain trip link','bad');throw new Error(d.error||'Could not create captain trip link');}await navigator.clipboard.writeText(d.captainTripUrl);showBookingStatus(id,'Captain trip link copied.');setTimeout(()=>loadBookings(),900);}
    async function sendBookingConfirmation(id){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;showBookingStatus(id,'Sending confirmation email...');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/send-confirmation`,{method:'POST',headers:adminHeaders()});const d=await r.json();if(r.status===501){await navigator.clipboard.writeText(customerReply(booking,'confirm'));showBookingStatus(id,'Customer email is not configured. Confirmation copied instead.','bad');return;}if(!r.ok){showBookingStatus(id,d.error||'Could not send confirmation','bad');throw new Error(d.error||'Could not send confirmation');}showBookingStatus(id,'Confirmation email sent.');setTimeout(()=>loadBookings(),1200);}
    function agreementPacketMissingFields(booking,draft){const missing=[];if(!booking.boatId)missing.push('boat');if(!draft.captainId)missing.push('captain');if(!draft.charterDate)missing.push('date');if(!draft.startTime)missing.push('start time');if(!draft.durationHours)missing.push('hours');return missing;}
    async function postAgreementPacket(id,booking,draft,{reload=true}={}){const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/send-agreement-packet`,{method:'POST',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({signingUrl:draft.signingUrl})});const d=await r.json();if(r.status===501){await navigator.clipboard.writeText(agreementPacket(booking));showBookingStatus(id,'Customer email is not configured. Agreement packet copied instead.','bad');return {copied:true};}if(!r.ok){showBookingStatus(id,d.error||'Could not send agreement packet','bad');throw new Error(d.error||'Could not send agreement packet');}if(reload)setTimeout(()=>loadBookings(),1200);return d;}
    async function sendAgreementPacket(id){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;const draft=bookingDraft(id);const missing=agreementPacketMissingFields(booking,draft);if(missing.length){const message=`Add ${missing.join(', ')} before sending the agreement packet.`;showBookingStatus(id,message,'bad',{scroll:true});alert(message);return;}setAgreementSendBusy(id,true);try{showBookingStatus(id,'Saving booking details before sending agreement...','info');await saveBooking(id,{silent:true});showBookingStatus(id,'Sending guided agreement packet...','info');const result=await postAgreementPacket(id,booking,draft,{reload:false});await loadBookings();showBookingStatus(id,result?.copied?'Customer email is not configured. Agreement packet copied instead.':'Agreement packet sent. Resend status updated.',result?.copied?'bad':'good');}catch(e){showBookingStatus(id,e.message||'Could not send agreement packet','bad');throw e;}finally{setAgreementSendBusy(id,false);}}
    async function sendCaptainPacket(id){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;showBookingStatus(id,'Sending captain packet...');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/send-captain-packet`,{method:'POST',headers:adminHeaders()});const d=await r.json();if(r.status===501){await navigator.clipboard.writeText(captainPacket(booking));showBookingStatus(id,'Captain email is not configured. Packet copied instead.','bad');return;}if(!r.ok){showBookingStatus(id,d.error||'Could not send captain packet','bad');throw new Error(d.error||'Could not send captain packet');}showBookingStatus(id,'Captain packet sent.');setTimeout(()=>loadBookings(),1200);}
    async function sendFinalInvoice(id){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;showBookingStatus(id,'Saving settlement before sending final invoice...');await saveSettlement(id,{silent:true});showBookingStatus(id,'Sending final invoice email...');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/send-final-invoice`,{method:'POST',headers:adminHeaders()});const d=await r.json();if(r.status===501){await navigator.clipboard.writeText(finalInvoiceText(booking));showBookingStatus(id,'Customer email is not configured. Final invoice copied instead.','bad');return;}if(!r.ok){showBookingStatus(id,d.error||'Could not send final invoice','bad');throw new Error(d.error||'Could not send final invoice');}showBookingStatus(id,'Final invoice sent.');setTimeout(()=>loadBookings(),1200);}
    function safeBookingFile(file){const safeTypes=new Set(['application/pdf','application/msword','application/vnd.openxmlformats-officedocument.wordprocessingml.document','application/vnd.ms-excel','application/vnd.openxmlformats-officedocument.spreadsheetml.sheet','text/plain','text/csv','application/rtf','image/jpeg','image/png','image/webp']);const safeExt=/\.(pdf|doc|docx|xls|xlsx|csv|txt|rtf|jpe?g|png|webp)$/i;return safeTypes.has(file.type)||safeExt.test(file.name||'');}
    async function addBookingDocument(id){const input=bookingList.querySelector(`[data-doc-files="${CSS.escape(id)}"]`);const files=[...(input?.files||[])];if(!files.length){showBookingStatus(id,'Choose at least one file to attach.','bad');return;}const unsafe=files.filter(file=>!safeBookingFile(file));if(unsafe.length){showBookingStatus(id,`Unsupported file type: ${unsafe.map(f=>f.name).join(', ')}`,'bad');if(input)input.value='';return;}showBookingStatus(id,`Attaching ${files.length} file(s)...`,'info');const form=new FormData();files.forEach(file=>form.append('file',file));form.append('documentType','attachment');form.append('status','uploaded');form.append('audience','office,captain');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/documents`,{method:'POST',headers:adminHeaders(),body:form});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not attach document');if(input)input.value='';showBookingStatus(id,`Attached ${d.documents?.length||files.length} file(s).`);setTimeout(()=>loadBookings(),900);}
    function updateSettlementPreview(id){const booking=state.bookings.find(b=>b.id===id);const el=bookingList.querySelector(`[data-settlement-preview="${CSS.escape(id)}"]`);if(!booking||!el)return;const closeout=closeoutDraft(id);const calc=payoutMath(booking,closeout);el.innerHTML=`<div><span>Miles traveled</span><strong>${calc.milesTraveled}</strong></div><div><span>Fuel charge</span><strong>${money2(calc.mileageCharge)}</strong></div><div><span>Additional charges</span><strong>${money2(closeout.additionalCharges)}</strong></div><div><span>Captain pay</span><strong>${money2(calc.captainPay)}</strong></div><div><span>Owner payout</span><strong>${money2(calc.ownerPayout)}</strong></div><div><span>Cove commission</span><strong>${money2(calc.coveCommission)}</strong></div><div><span>Fuel refund</span><strong>${money2(calc.fuelDepositRefund)}</strong></div>`;}
    function bindSettlementInputs(){bookingList.querySelectorAll('[data-settlement-preview]').forEach(el=>updateSettlementPreview(el.dataset.settlementPreview));bookingList.querySelectorAll('[data-add-additional]').forEach(btn=>btn.onclick=()=>addAdditionalChargeRow(btn.dataset.addAdditional));bookingList.querySelectorAll('[data-remove-additional]').forEach(btn=>btn.onclick=()=>{const id=btn.dataset.removeAdditional;btn.closest('[data-additional-row]')?.remove();rememberSettlementDraft(id);updateSettlementPreview(id);});bookingList.querySelectorAll('[data-closeout-hours],[data-closeout-miles],[data-closeout-mileage-rate],[data-closeout-cleaning],[data-closeout-captain-rate],[data-closeout-owner-split],[data-closeout-cove-split],[data-closeout-payment],[data-closeout-notes],[data-additional-desc],[data-additional-amount]').forEach(input=>{input.oninput=()=>{const id=input.getAttributeNames().map(n=>n.startsWith('data-closeout-')?input.getAttribute(n):'').find(Boolean)||input.closest('[data-additional-row]')?.dataset.additionalRow;rememberSettlementDraft(id);updateSettlementPreview(id);};input.onchange=input.oninput;});}
    async function saveSettlement(id,options={}){const closeout=closeoutDraft(id);const payload={...closeout,customerPaidStatus:closeout.paymentStatus,notes:closeout.notes,closeTrip:Boolean(options.closeTrip)};if(!options.silent)showBookingStatus(id,'Saving settlement...');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/settlement`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(payload)});const d=await r.json();if(!r.ok){showBookingStatus(id,d.error||'Could not save settlement','bad');throw new Error(d.error||'Could not save settlement');}delete state.settlementDrafts[id];if(!options.silent){showBookingStatus(id,'Settlement saved.');setTimeout(()=>loadBookings(),900);}return d;}
    async function completeTrip(id){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;setCompleteTripBusy(id,true);try{showBookingStatus(id,'Completing trip...','info');await saveSettlement(id,{closeTrip:true,silent:true});const draft=bookingDraft(id);const closeout=closeoutDraft(id);draft.status='completed';draft.officeNotes=stampNote(draft.officeNotes,`Trip completed. Actual hours: ${closeout.actualHours||draft.durationHours}. Payment: ${closeout.paymentStatus}. Closeout notes: ${closeout.notes||'None'}`);const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(draft)});const d=await r.json();if(!r.ok){showBookingStatus(id,d.error||'Could not complete trip','bad');throw new Error(d.error||'Could not complete trip');}const statusEl=bookingList.querySelector(`[data-booking-status="${CSS.escape(id)}"]`);if(statusEl)statusEl.value='completed';showBookingStatus(id,'Trip completed.');setTimeout(()=>loadBookings(),1200);}finally{setCompleteTripBusy(id,false);}}
    async function saveBooking(id,options={}){if(!options.silent){showBookingStatus(id,'Saving booking...','info');setBookingSaveBusy(id,true);}const payload=bookingDraft(id);const current=state.bookings.find(b=>b.id===id)||{};if(payload.status==='cancelled'&&current.status!=='cancelled'&&!payload.cancellationReason){const reason=cancellationReason(id);if(!reason){setBookingSaveBusy(id,false);return;}payload.cancellationReason=reason;payload.officeNotes=stampNote(payload.officeNotes,`Booking cancelled. Reason: ${reason}`);}try{const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(payload)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not save booking');if(bookingList.querySelector(`[data-settlement-preview="${CSS.escape(id)}"]`)){if(!options.silent)showBookingStatus(id,'Saving booking and settlement...','info');await saveSettlement(id,{silent:true});}if(!options.silent){await loadBookings();showBookingStatus(id,'Booking saved.');}return d;}catch(e){if(!options.silent)showBookingStatus(id,e.message||'Could not save booking','bad');throw e;}finally{if(!options.silent)setBookingSaveBusy(id,false);}}
    async function quickBookingAction(id,action){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;const draft=bookingDraft(id);if(action==='confirm'){const missing=agreementPacketMissingFields(booking,draft);if(missing.length){const message=`Add ${missing.join(', ')} before confirming and sending the agreement packet.`;showBookingStatus(id,message,'bad',{scroll:true});alert(message);return;}setConfirmSendBusy(id,true);}if(action==='cancel'){const reason=cancellationReason(id);if(!reason)return;draft.cancellationReason=reason;}try{const status=action==='confirm'?'confirmed':action==='cancel'?'cancelled':'declined';const message=action==='confirm'?'Confirmed booking and sent customer agreement packet.':action==='cancel'?`Cancelled booking. Reason: ${draft.cancellationReason}`:'Declined request and copied customer decline message.';draft.status=status;draft.officeNotes=stampNote(draft.officeNotes,message);showBookingStatus(id,action==='confirm'?'Confirming booking and sending agreement packet...':action==='cancel'?'Cancelling booking...':'Declining booking...','info');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(draft)});const d=await r.json();if(!r.ok){showBookingStatus(id,d.error||'Could not update booking','bad');throw new Error(d.error||'Could not update booking');}let finalMessage='Booking updated.';let finalTone='good';if(action==='confirm'){try{const result=await postAgreementPacket(id,booking,draft,{reload:false});finalMessage=result?.copied?'Booking confirmed. Customer email is not configured; agreement packet copied.':'Booking confirmed. Agreement packet sent.';finalTone=result?.copied?'bad':'good';}catch(e){await loadBookings();showBookingStatus(id,`Booking confirmed, but agreement packet failed: ${e.message}`,'bad');return;}}if(action==='decline'){await navigator.clipboard.writeText(customerReply(booking,'decline'));finalMessage='Booking declined. Decline reply copied.';}if(action==='cancel')finalMessage='Booking cancelled. Reason saved to customer record.';await loadBookings();showBookingStatus(id,finalMessage,finalTone);}finally{if(action==='confirm')setConfirmSendBusy(id,false);}}
    function refreshBookingsNow(){const active=document.activeElement;if(state.selectedBookingId&&!document.getElementById('bookingDetailScreen')?.classList.contains('hidden'))return;if(Date.now()-state.lastSettlementEditAt<60000)return;if(active?.closest?.('.settlement-panel'))return;if(active?.matches?.('[data-booking-status],[data-booking-captain],[data-booking-date],[data-booking-time],[data-booking-duration],[data-booking-notes],[data-booking-signing],[data-doc-files]'))return;loadBookings({silent:true});}
    function startBookingAutoRefresh(){setInterval(()=>{if(!document.hidden)refreshBookingsNow();},10000);window.addEventListener('focus',refreshBookingsNow);document.addEventListener('visibilitychange',()=>{if(!document.hidden)refreshBookingsNow();});}
    async function loadMedia(){if(!state.selectedBoatId)return;const r=await fetch(`${api()}/api/v1/media?entityType=boat&entityId=${encodeURIComponent(state.selectedBoatId)}`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load media');state.media=d;renderMedia();}
    function renderMedia(){const photos=sortMedia(state.media.filter(m=>m.mediaType==='photos'));const videos=sortMedia(state.media.filter(m=>m.mediaType==='videos'));const cover=photos.find(m=>m.isCover);coverMedia.innerHTML=cover?mediaCard(cover,false):'<div class="empty-media">No cover selected.</div>';renderCoverCrop(cover);photoGallery.innerHTML=photos.length?photos.map(m=>mediaCard(m,true)).join(''):'<div class="empty-media">No gallery photos yet.</div>';videoGallery.innerHTML=videos.length?videos.map(m=>mediaCard(m,true)).join(''):'<div class="empty-media">No videos yet.</div>';bindMediaDrag(photoGallery,'photos');bindMediaDrag(videoGallery,'videos');document.querySelectorAll('[data-cover-id]').forEach(btn=>btn.onclick=()=>setCover(btn.dataset.coverId).catch(e=>alert(e.message)));document.querySelectorAll('[data-delete-media]').forEach(btn=>btn.onclick=()=>deleteMedia(btn.dataset.deleteMedia).catch(e=>alert(e.message)));document.querySelectorAll('[data-caption-id]').forEach(input=>{input.onkeydown=e=>{if(e.key==='Enter'){e.preventDefault();input.blur();}};input.onchange=()=>saveCaption(input.dataset.captionId,input.value).catch(e=>alert(e.message));});}
    function sortMedia(items){return [...items].sort((a,b)=>Number(a.sortOrder||0)-Number(b.sortOrder||0)||String(a.createdAt||'').localeCompare(String(b.createdAt||'')));}
    function bindMediaDrag(container,mediaType){container.querySelectorAll('.media-card').forEach(card=>{card.ondragstart=e=>{card.classList.add('dragging');e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain',card.dataset.id);};card.ondragend=()=>card.classList.remove('dragging');card.ondragover=e=>{e.preventDefault();e.dataTransfer.dropEffect='move';};card.ondrop=e=>{e.preventDefault();reorderMedia(e.dataTransfer.getData('text/plain'),card.dataset.id,mediaType).catch(err=>alert(err.message));};});}
    function mediaCard(m,draggable=true){const caption=m.title||'';const style=`--media-x:${cropNumber(m.focalX,50)}%;--media-y:${cropNumber(m.focalY,50)}%;--media-zoom:${cropNumber(m.zoom,1)}`;const media=m.mediaType==='videos'?`<video src="${esc(m.url)}" controls></video>`:`<img src="${esc(m.url)}" alt="${esc(m.alt||m.title||'Boat media')}">`;return `<article class="media-card ${m.isCover?'cover':''}" style="${style}" draggable="${draggable?'true':'false'}" data-id="${esc(m.id)}" data-type="${esc(m.mediaType)}">${media}<input data-caption-id="${esc(m.id)}" value="${esc(caption)}" placeholder="spacious interior"><span class="muted">${m.isCover?'Cover photo':`Sort ${m.sortOrder}`}</span><div class="actions">${m.mediaType==='photos'?`<button class="btn light" type="button" data-cover-id="${esc(m.id)}">Set Cover</button>`:''}<button class="btn danger" type="button" data-delete-media="${esc(m.id)}">Delete</button></div></article>`}
    function renderMediaError(message){coverMedia.innerHTML=`<div class="empty-media">${message}</div>`;photoGallery.innerHTML='<div class="empty-media">Media unavailable.</div>';videoGallery.innerHTML='<div class="empty-media">Media unavailable.</div>';}
    function renderCoverCrop(cover){if(!cover){coverCropEditor.classList.add('hidden');coverCropDraft=null;return;}coverCropEditor.classList.remove('hidden');coverCropDraft={id:cover.id,focalX:cropNumber(cover.focalX,50),focalY:cropNumber(cover.focalY,50),zoom:cropNumber(cover.zoom,1)};if(!coverCropper&&window.AdminImageCropper){coverCropper=new AdminImageCropper(document.getElementById('coverPhotoCropper'),{imageUrl:cover.url,focalX:coverCropDraft.focalX,focalY:coverCropDraft.focalY,zoom:coverCropDraft.zoom,frame:'wide',hint:'Adjust the cover photo crop used by public fleet cards and the boat detail hero.',onChange:v=>{coverCropDraft={...coverCropDraft,...v};coverCropStatus.textContent='Crop adjusted. Save Cover Crop to persist.';}});}else if(coverCropper){coverCropper.setImage(cover.url);coverCropper.setValue(coverCropDraft);}coverCropStatus.textContent='Adjust the public cover framing for fleet cards and the boat detail hero.';}
    async function saveCurrentCoverCrop(){if(!coverCropDraft?.id)return;setButtonsBusy(['saveCoverCrop'],true);coverCropStatus.textContent='Saving cover crop...';try{const r=await fetch(`${api()}/api/v1/media/${encodeURIComponent(coverCropDraft.id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(coverCropDraft)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not save cover crop');coverCropStatus.textContent='Cover crop saved.';await loadMedia();}catch(e){coverCropStatus.textContent=e.message||'Could not save cover crop';throw e;}finally{setButtonsBusy(['saveCoverCrop'],false);}}
    async function setCover(id){const r=await fetch(`${api()}/api/v1/media/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({isCover:true})});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not set cover');await loadMedia();}
    async function deleteMedia(id){const item=state.media.find(m=>m.id===id);const label=item?.title||item?.url||'this media item';if(!confirm(`Delete ${label}? This removes it from the boat gallery.`))return;const r=await fetch(`${api()}/api/v1/media/${encodeURIComponent(id)}`,{method:'DELETE',headers:adminHeaders()});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not delete media');await loadMedia();}
    async function saveCaption(id,title){const clean=title.trim();const item=state.media.find(m=>m.id===id);if(!item||clean===String(item.title||''))return;const r=await fetch(`${api()}/api/v1/media/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({title:clean,alt:clean})});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not save caption');state.media=state.media.map(m=>m.id===id?{...m,title:clean,alt:clean}:m);}
    async function reorderMedia(sourceId,targetId,mediaType){if(!sourceId||!targetId||sourceId===targetId)return;const items=sortMedia(state.media.filter(m=>m.mediaType===mediaType));const from=items.findIndex(m=>m.id===sourceId);const to=items.findIndex(m=>m.id===targetId);if(from<0||to<0)return;const [moved]=items.splice(from,1);items.splice(to,0,moved);state.media=state.media.map(item=>item.mediaType===mediaType?{...item,sortOrder:items.findIndex(m=>m.id===item.id)}:item);renderMedia();await Promise.all(items.map((m,i)=>fetch(`${api()}/api/v1/media/${encodeURIComponent(m.id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({sortOrder:i})}).then(async r=>{if(!r.ok)throw new Error((await r.json()).error||'Could not sort media')})));await loadMedia();}
    async function uploadFiles(files,mediaType,statusEl){if(!state.selectedBoatId){alert('Save/select a boat first.');return;}if(!files.length){alert('Choose at least one file first.');return;}const b=state.boats.find(x=>x.id===state.selectedBoatId);statusEl.textContent=`Uploading ${files.length} file(s)...`;let count=0;for(const file of files){const form=new FormData();form.append('file',file);form.append('entityType','boat');form.append('entityId',b.id);form.append('entitySlug',b.slug||b.id);form.append('mediaType',mediaType);form.append('title',file.name);const r=await fetch(`${api()}/api/v1/media`,{method:'POST',headers:adminHeaders(),body:form});const d=await r.json();if(!r.ok)throw new Error(d.error||'Upload failed');count++;}await loadMedia();statusEl.textContent=`Uploaded ${count} file(s).`;}
    async function uploadCaptainHeadshot(){if(!state.selectedCaptainId){captainPhotoStatus.textContent='Save/select a captain before uploading a headshot.';return;}const file=captainPhotoFile.files?.[0];if(!file){captainPhotoStatus.textContent='Choose a headshot file first.';return;}const captain=state.captains.find(c=>c.id===state.selectedCaptainId);captainPhotoStatus.textContent='Uploading captain photo...';const form=new FormData();form.append('file',file);form.append('entityType','captain');form.append('entityId',captain.id);form.append('entitySlug',captain.name||captain.id);form.append('mediaType','photos');form.append('title',file.name);form.append('isCover','true');const r=await fetch(`${api()}/api/v1/media`,{method:'POST',headers:adminHeaders(),body:form});const d=await r.json();if(!r.ok)throw new Error(d.error||'Photo upload failed');captainPhotoUrl.value=d.url;setCaptainCropInputs();updateCaptainPhotoPreview();captainPhotoStatus.textContent='Photo uploaded. Saving captain...';await saveCurrentCaptain();captainPhotoFile.value='';captainPhotoStatus.textContent='Photo saved.';}
